 fichas.es/infantil/3-anos/matematicas/numero-1/\r\n *   â fichas.es/primaria/1-primaria/lengua/consonante-m/\r\n * \r\n * Fallback automĂĄtico si falta taxonomĂ­a:\r\n *   â ïž fichas.es/ficha/slug-sin-taxonomias/\r\n * \r\n * VersiĂłn: 1.0 PRODUCCIĂN\r\n * Fecha: 3 febrero 2026\r\n * ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n */\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 1. MODIFICAR ESTRUCTURA REWRITE DEL CPT \'FICHA\'\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_filter(\'register_post_type_args\', \'fichas_hierarchical_rewrite\', 10, 2);\r\nfunction fichas_hierarchical_rewrite($args, $post_type) {\r\n    if (\'ficha\' !== $post_type) {\r\n        return $args;\r\n    }\r\n    \r\n    $args[\'rewrite\'] = array(\r\n        \'slug\'         => \'%nivel-educativo%/%curso%/%asignatura%\',\r\n        \'with_front\'   => false,\r\n        \'hierarchical\' => false\r\n    );\r\n    \r\n    return $args;\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 2. GENERAR URL JERĂRQUICA REAL (reemplazar placeholders)\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_filter(\'post_type_link\', \'fichas_build_hierarchical_url\', 10, 2);\r\nfunction fichas_build_hierarchical_url($post_link, $post) {\r\n    if (\'ficha\' !== $post->post_type) {\r\n        return $post_link;\r\n    }\r\n    \r\n    // Obtener taxonomĂ­as\r\n    $nivel      = wp_get_object_terms($post->ID, \'nivel-educativo\');\r\n    $curso      = wp_get_object_terms($post->ID, \'curso\');\r\n    $asignatura = wp_get_object_terms($post->ID, \'asignatura\');\r\n    \r\n    // Validar existencia\r\n    $nivel_ok      = (!is_wp_error($nivel) && !empty($nivel));\r\n    $curso_ok      = (!is_wp_error($curso) && !empty($curso));\r\n    $asignatura_ok = (!is_wp_error($asignatura) && !empty($asignatura));\r\n    \r\n    // Fallback si falta alguna taxonomĂ­a\r\n    if (!$nivel_ok || !$curso_ok || !$asignatura_ok) {\r\n        return home_url(\'/ficha/\' . $post->post_name . \'/\');\r\n    }\r\n    \r\n    // Construir URL jerĂĄrquica\r\n    return home_url(sprintf(\r\n        \'/%s/%s/%s/%s/\',\r\n        $nivel[0]->slug,\r\n        $curso[0]->slug,\r\n        $asignatura[0]->slug,\r\n        $post->post_name\r\n    ));\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 3. REGLAS DE REWRITE PARA WORDPRESS\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_action(\'init\', \'fichas_add_custom_rewrite_rules\', 20);\r\nfunction fichas_add_custom_rewrite_rules() {\r\n    $niveles = get_terms(array(\r\n        \'taxonomy\'   => \'nivel-educativo\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    $cursos = get_terms(array(\r\n        \'taxonomy\'   => \'curso\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    $asignaturas = get_terms(array(\r\n        \'taxonomy\'   => \'asignatura\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    if (is_wp_error($niveles) || empty($niveles) ||\r\n        is_wp_error($cursos) || empty($cursos) ||\r\n        is_wp_error($asignaturas) || empty($asignaturas)) {\r\n        return;\r\n    }\r\n    \r\n    $niveles_escaped     = array_map(\'preg_quote\', $niveles);\r\n    $cursos_escaped      = array_map(\'preg_quote\', $cursos);\r\n    $asignaturas_escaped = array_map(\'preg_quote\', $asignaturas);\r\n    \r\n    $niveles_pattern     = \'(\' . implode(\'|\', $niveles_escaped) . \')\';\r\n    $cursos_pattern      = \'(\' . implode(\'|\', $cursos_escaped) . \')\';\r\n    $asignaturas_pattern = \'(\' . implode(\'|\', $asignaturas_escaped) . \')\';\r\n    \r\n    // Regla principal: /nivel/curso/asignatura/slug/\r\n    add_rewrite_rule(\r\n        \'^\' . $niveles_pattern . \'/\' . $cursos_pattern . \'/\' . $asignaturas_pattern . \'/([^/]+)/?$\',\r\n        \'index.php?ficha=$matches[4]\',\r\n        \'top\'\r\n    );\r\n    \r\n    // Regla fallback: /ficha/slug/\r\n    add_rewrite_rule(\r\n        \'^ficha/([^/]+)/?$\',\r\n        \'index.php?ficha=$matches[1]\',\r\n        \'bottom\'\r\n    );\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 4. AUTO-FLUSH REWRITE RULES AL MODIFICAR TAXONOMĂAS\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_action(\'created_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nadd_action(\'edited_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nadd_action(\'delete_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nfunction fichas_schedule_flush_rules($term_id, $tt_id, $taxonomy) {\r\n    $target_taxonomies = array(\'nivel-educativo\', \'curso\', \'asignatura\');\r\n    \r\n    if (in_array($taxonomy, $target_taxonomies)) {\r\n        set_transient(\'fichas_needs_flush_rules\', 1, 60);\r\n    }\r\n}\r\n\r\nadd_action(\'init\', \'fichas_maybe_flush_rules\', 999);\r\nfunction fichas_maybe_flush_rules() {\r\n    if (get_transient(\'fichas_needs_flush_rules\')) {\r\n        flush_rewrite_rules(false);\r\n        delete_transient(\'fichas_needs_flush_rules\');\r\n    }\r\n}\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-02-03 13:59:09\";}i:1;a:14:{s:2:\"id\";i:366;s:5:\"title\";s:43:\"ENQUEUE UNIFICADO E INTELIGENTE - Fichas.es\";s:4:\"code\";s:3998:\"/**\r\n * ENQUEUE UNIFICADO E INTELIGENTE - Fichas.es\r\n * Carga CSS/JS solo si la ficha los necesita (detecciĂłn automĂĄtica)\r\n * VersiĂłn 2.2 - Con soporte PDF\r\n */\r\n\r\nfunction fichas_enqueue_inteligente() {\r\n    // Solo en single ficha\r\n    if (!is_singular(\'ficha\')) return;\r\n\r\n    // Obtener contenido de la ficha actual\r\n    global $post;\r\n    $contenido = get_field(\'contenido_ficha_html\', $post->ID);\r\n    if (empty($contenido)) {\r\n        $contenido = $post->post_content;\r\n    }\r\n\r\n    // ============================================\r\n    // 1. LIBRERĂAS PDF (si usas descarga PDF)\r\n    // ============================================\r\n    \r\n    // html2canvas\r\n    wp_enqueue_script(\'html2canvas\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js\',\r\n        array(), \'1.4.1\', true);\r\n    \r\n    // jsPDF\r\n    wp_enqueue_script(\'jspdf\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js\',\r\n        array(), \'2.5.1\', true);\r\n    \r\n    // html2pdf (depende de html2canvas y jspdf)\r\n    wp_enqueue_script(\'html2pdf\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js\',\r\n        array(\'html2canvas\', \'jspdf\'), \'0.10.1\', true);\r\n\r\n    // ============================================\r\n    // 2. ARCHIVOS BASE (siempre se cargan)\r\n    // ============================================\r\n    \r\n    wp_enqueue_style(\'fichas-base\',\r\n        get_stylesheet_directory_uri() . \'/css/fichas.css\',\r\n        array(), \'2.5\');\r\n    \r\n wp_enqueue_script(\'fichas-base\',\r\n    get_stylesheet_directory_uri() . \'/js/fichas.js\',\r\n    array(), \'2.9\', true); // â VersiĂłn 2.9\r\n\r\n    // ============================================\r\n    // 3. ADDONS (carga condicional inteligente)\r\n    // ============================================\r\n    \r\n    $addons = array(\r\n        \'truefalse\' => array(\r\n            \'detectores\' => array(\'bloque-truefalse\', \'ejercicio-truefalse\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'fillblanks\' => array(\r\n            \'detectores\' => array(\'bloque-fillblanks\', \'ejercicio-fillblanks\', \'fillblank-input\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'wordsearch\' => array(\r\n            \'detectores\' => array(\'bloque-wordsearch\', \'ejercicio-wordsearch\', \'wordsearch-table\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'dragdrop\' => array(\r\n            \'detectores\' => array(\'ejercicio-dragdrop\', \'dragdrop-item\', \'dragdrop-zone\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'memory\' => array(\r\n            \'detectores\' => array(\'ejercicio-memory\', \'memory-card\', \'memory-grid\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'trazo\' => array(\r\n            \'detectores\' => array(\'ejercicio-trazo\', \'canvas-trazo\', \'canvas-container\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        )\r\n    );\r\n\r\n    // Detectar y cargar addons necesarios\r\n    foreach ($addons as $addon => $config) {\r\n        $necesita_addon = false;\r\n\r\n        foreach ($config[\'detectores\'] as $detector) {\r\n            if (stripos($contenido, $detector) !== false) {\r\n                $necesita_addon = true;\r\n                break;\r\n            }\r\n        }\r\n\r\n        if ($necesita_addon && $config[\'css\']) {\r\n            wp_enqueue_style(\r\n                $addon . \'-addon\',\r\n                get_stylesheet_directory_uri() . \'/css/\' . $addon . \'-addon.css\',\r\n                array(\'fichas-base\'),\r\n                \'2.2\'\r\n            );\r\n        }\r\n\r\n        if ($necesita_addon && $config[\'js\']) {\r\n            wp_enqueue_script(\r\n                $addon . \'-addon\',\r\n                get_stylesheet_directory_uri() . \'/js/\' . $addon . \'-addon.js\',\r\n                array(\'fichas-base\'),\r\n                \'2.2\',\r\n                true\r\n            );\r\n        }\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_enqueue_inteligente\');\r\n\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-02-02 12:22:05\";}i:2;a:14:{s:2:\"id\";i:362;s:5:\"title\";s:37:\"Contador de visualizaciones de fichas\";s:4:\"code\";s:1143:\"/**\r\n * Contador de visualizaciones de fichas\r\n * Incrementa automĂĄticamente cada vez que se visita una ficha\r\n */\r\n\r\n// Incrementar contador al visitar una ficha\r\nfunction fichas_incrementar_vistas() {\r\n    if (is_singular(\'ficha\')) {\r\n        global $post;\r\n        \r\n        // Obtener vistas actuales\r\n        $vistas = get_post_meta($post->ID, \'fichas_vistas\', true);\r\n        $vistas = empty($vistas) ? 0 : intval($vistas);\r\n        \r\n        // Incrementar\r\n        $vistas++;\r\n        \r\n        // Guardar\r\n        update_post_meta($post->ID, \'fichas_vistas\', $vistas);\r\n    }\r\n}\r\nadd_action(\'wp_head\', \'fichas_incrementar_vistas\');\r\n\r\n// FunciĂłn helper para obtener vistas en templates\r\nfunction fichas_get_vistas($post_id = null) {\r\n    if (!$post_id) {\r\n        global $post;\r\n        $post_id = $post->ID;\r\n    }\r\n    \r\n    $vistas = get_post_meta($post_id, \'fichas_vistas\', true);\r\n    return empty($vistas) ? 0 : intval($vistas);\r\n}\r\n\r\n// Formatear nĂșmero con separador de miles\r\nfunction fichas_format_vistas($post_id = null) {\r\n    $vistas = fichas_get_vistas($post_id);\r\n    return number_format($vistas, 0, \',\', \'.\');\r\n}\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-01-30 09:28:33\";}i:3;a:14:{s:2:\"id\";i:297;s:5:\"title\";s:24:\"Encolar CSS de Hub Nivel\";s:4:\"code\";s:623:\"/**\r\n * Encolar CSS de Hub Nivel\r\n */\r\nfunction fichas_enqueue_hub_nivel_css() {\r\n    // Solo cargar en pĂĄginas de hub de nivel\r\n    if (is_page_template(\'page-hub-nivel-primaria.php\') || \r\n        is_page_template(\'page-hub-nivel-infantil.php\') ||\r\n        is_page(array(\'primaria\', \'infantil\', \'secundaria\'))) {\r\n        \r\n        wp_enqueue_style(\r\n            \'hub-nivel-css\',\r\n            get_stylesheet_directory_uri() . \'/css/hub-nivel.css\',\r\n            array(), // Sin dependencias\r\n            \'1.0.0\',\r\n            \'all\'\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_enqueue_hub_nivel_css\');\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-01-29 10:51:30\";}i:4;a:14:{s:2:\"id\";i:170;s:5:\"title\";s:33:\"Encolar CSS Front-Page (Homepage)\";s:4:\"code\";s:763:\"/**\r\n * TĂ­tulo: Encolar CSS Front-Page (Homepage)\r\n * DescripciĂłn: Carga front-page.css solo en la pĂĄgina de inicio\r\n * VersiĂłn: 1.0\r\n * Prioridad: 20\r\n */\r\n\r\nfunction encolar_css_homepage() {\r\n    // CSS general (todas las pĂĄginas)\r\n    wp_enqueue_style(\r\n        \'fichas-css\', \r\n        get_stylesheet_directory_uri() . \'/css/fichas.css\',\r\n        array(),\r\n        \'2.0\'\r\n    );\r\n    \r\n    // CSS homepage (solo front-page.php)\r\n    if (is_front_page()) {\r\n        wp_enqueue_style(\r\n            \'front-page-css\', \r\n            get_stylesheet_directory_uri() . \'/css/front-page.css\',\r\n            array(\'fichas-css\'), // âŹïž Depende de fichas.css\r\n            \'1.0\'\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'encolar_css_homepage\', 20);\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-01-22 10:49:37\";}i:5;a:14:{s:2:\"id\";i:145;s:5:\"title\";s:48:\"Genera breadcrumbs (migas de pan) con Schema.org\";s:4:\"code\";s:5622:\"/**\r\n * Genera breadcrumbs de navegaciĂłn con Schema.org\r\n * NO confundir con .ficha-breadcrumb-taxonomias (badges dentro de header)\r\n * VERSIĂN 2.0: Soporte para tema-estacional con prioridad sobre asignatura\r\n */\r\nfunction fichas_breadcrumbs() {\r\n    if (is_front_page()) {\r\n        return;\r\n    }\r\n    \r\n    $breadcrumbs = array();\r\n    $home = array(\r\n        \'name\' => \'Inicio\',\r\n        \'url\' => home_url(\'/\')\r\n    );\r\n    \r\n    $breadcrumbs[] = $home;\r\n    \r\n    // SINGLE FICHA\r\n    if (is_singular(\'ficha\')) {\r\n        $post_id = get_the_ID();\r\n        \r\n        // Nivel educativo\r\n        $niveles = get_the_terms($post_id, \'nivel-educativo\');\r\n        if ($niveles && !is_wp_error($niveles)) {\r\n            $nivel = $niveles[0];\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $nivel->name,\r\n                \'url\' => home_url(\'/\' . $nivel->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // Curso\r\n        $cursos = get_the_terms($post_id, \'curso\');\r\n        if ($cursos && !is_wp_error($cursos)) {\r\n            $curso = $cursos[0];\r\n            $nivel_slug = $nivel ? $nivel->slug : \'primaria\';\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $curso->name,\r\n                \'url\' => home_url(\'/\' . $nivel_slug . \'/\' . $curso->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // PRIORIDAD: Tema Estacional > Asignatura\r\n        $tema_estacional = get_the_terms($post_id, \'tema-estacional\');\r\n        $asignaturas = get_the_terms($post_id, \'asignatura\');\r\n        \r\n        if ($tema_estacional && !is_wp_error($tema_estacional)) {\r\n            // SI HAY TEMA ESTACIONAL: Mostrar ese\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $tema_estacional[0]->name,\r\n                \'url\' => home_url(\'/\' . ($nivel ? $nivel->slug : \'infantil\') . \'/estacional/\')\r\n            );\r\n        } elseif ($asignaturas && !is_wp_error($asignaturas) && $asignaturas[0]->slug !== \'todas\') {\r\n            // SI NO HAY ESTACIONAL pero SĂ asignatura vĂĄlida (y no es \"Todas\"): Mostrar asignatura\r\n            $asignatura = $asignaturas[0];\r\n            $nivel_slug = $nivel ? $nivel->slug : \'primaria\';\r\n            $curso_slug = $curso ? $curso->slug : \'1-primaria\';\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $asignatura->name,\r\n                \'url\' => home_url(\'/\' . $nivel_slug . \'/\' . $curso_slug . \'/\' . $asignatura->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // Ficha actual\r\n        $breadcrumbs[] = array(\r\n            \'name\' => get_the_title(),\r\n            \'url\' => \'\'\r\n        );\r\n    }\r\n    \r\n    // PĂGINA PERSONALIZADA (Hubs)\r\n    if (is_page()) {\r\n        // Detectar por URL\r\n        $url_parts = explode(\'/\', trim($_SERVER[\'REQUEST_URI\'], \'/\'));\r\n        \r\n        // Hub Nivel (ej: /primaria/)\r\n        if (count($url_parts) == 1 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(), // Usa el tĂ­tulo de la pĂĄgina\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n        // Hub Curso (ej: /primaria/1-primaria/)\r\n        elseif (count($url_parts) == 2 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($url_parts[0]),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\')\r\n            );\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(),\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n        // PĂĄgina Asignatura (ej: /primaria/1-primaria/matematicas/)\r\n        elseif (count($url_parts) == 3 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            // Nivel\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($url_parts[0]),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\')\r\n            );\r\n            // Curso\r\n            $curso_title = str_replace(\'-\', \' \', $url_parts[1]);\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($curso_title),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\' . $url_parts[1] . \'/\')\r\n            );\r\n            // Asignatura actual\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(),\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n    }\r\n    \r\n    // RENDERIZAR\r\n    if (count($breadcrumbs) > 1) {\r\n        echo \'<nav class=\"site-breadcrumbs\" aria-label=\"Breadcrumb\">\';\r\n        echo \'<ol class=\"breadcrumbs-list\" itemscope itemtype=\"https://schema.org/BreadcrumbList\">\';\r\n        \r\n        foreach ($breadcrumbs as $position => $crumb) {\r\n            $is_last = ($position == count($breadcrumbs) - 1);\r\n            \r\n            echo \'<li class=\"breadcrumb-nav-item\" itemprop=\"itemListElement\" itemscope itemtype=\"https://schema.org/ListItem\">\';\r\n            \r\n            if (!empty($crumb[\'url\']) && !$is_last) {\r\n                echo \'<a href=\"\' . esc_url($crumb[\'url\']) . \'\" itemprop=\"item\">\';\r\n                echo \'<span itemprop=\"name\">\' . esc_html($crumb[\'name\']) . \'</span>\';\r\n                echo \'</a>\';\r\n            } else {\r\n                echo \'<span itemprop=\"name\">\' . esc_html($crumb[\'name\']) . \'</span>\';\r\n            }\r\n            \r\n            echo \'<meta itemprop=\"position\" content=\"\' . ($position + 1) . \'\" />\';\r\n            echo \'</li>\';\r\n            \r\n            if (!$is_last) {\r\n                echo \'<li class=\"breadcrumb-separator\" aria-hidden=\"true\">âș</li>\';\r\n            }\r\n        }\r\n        \r\n        echo \'</ol>\';\r\n        echo \'</nav>\';\r\n    }\r\n}\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-01-29 10:30:03\";}i:6;a:14:{s:2:\"id\";i:130;s:5:\"title\";s:37:\"Preservar emojis en importaciones ACF\";s:4:\"code\";s:1187:\"/**\r\n * Preservar emojis UTF-8MB4 en importaciones de WP All Import hacia ACF\r\n * Campo: contenido_ficha_html\r\n */\r\n\r\n// 1. Forzar conexiĂłn UTF-8MB4 antes de cada importaciĂłn\r\nadd_action(\'pmxi_before_xml_import\', function($import_id) {\r\n    global $wpdb;\r\n    $wpdb->query(\"SET NAMES \'utf8mb4\'\");\r\n    $wpdb->query(\"SET CHARACTER SET utf8mb4\");\r\n    $wpdb->query(\"SET character_set_connection=utf8mb4\");\r\n}, 10, 1);\r\n\r\n// 2. Evitar que ACF sanitice el campo HTML\r\nadd_filter(\'acf/update_value/name=contenido_ficha_html\', function($value, $post_id, $field) {\r\n    // Devolver el valor sin modificar (sin sanitizaciĂłn)\r\n    return $value;\r\n}, 10, 3);\r\n\r\n// 3. Evitar que WP All Import sanitice campos ACF\r\nadd_filter(\'pmxi_acf_custom_field_value\', function($value, $pid, $name) {\r\n    if ($name === \'contenido_ficha_html\') {\r\n        // No aplicar wp_kses ni otras funciones de limpieza\r\n        return $value;\r\n    }\r\n    return $value;\r\n}, 10, 3);\r\n\r\n// 4. Preservar emojis al actualizar post meta directamente\r\nadd_filter(\'sanitize_post_meta_contenido_ficha_html\', function($meta_value, $meta_key, $object_type) {\r\n    // Devolver sin sanitizar\r\n    return $meta_value;\r\n}, 10, 3);\r\n\";s:9:\"code_type\";s:3:\"php\";s:8:\"location\";s:10:\"everywhere\";s:11:\"auto_insert\";i:1;s:13:\"insert_number\";i:1;s:9:\"use_rules\";b:0;s:5:\"rules\";a:0:{}s:8:\"priority\";i:10;s:14:\"location_extra\";s:0:\"\";s:20:\"shortcode_attributes\";a:0:{}s:13:\"compiled_code\";s:0:\"\";s:8:\"modified\";s:19:\"2026-01-19 10:19:56\";}}}','auto'),
