(24559,'_transient_cba1aab7f90f99256d9103976aa701d5','O:8:\"stdClass\":20:{s:11:\"new_version\";s:5:\"4.0.1\";s:14:\"stable_version\";s:5:\"4.0.1\";s:4:\"name\";s:10:\"ACF Add-On\";s:4:\"slug\";s:15:\"wpai-acf-add-on\";s:6:\"plugin\";s:0:\"\";s:3:\"url\";s:68:\"https://www.wpallimport.com/downloads/acf-import-add-on/?changelog=1\";s:12:\"last_updated\";s:19:\"2025-09-16 23:07:46\";s:8:\"homepage\";s:56:\"https://www.wpallimport.com/downloads/acf-import-add-on/\";s:8:\"sections\";a:2:{s:11:\"description\";s:132:\"<p>Learn more at <a href=\"http://www.wpallimport.com/\" target=\"_blank\" rel=\"noopener noreferrer\">http://www.wpallimport.com/</a></p>\";s:9:\"changelog\";s:13586:\"<h4>4.0.1</h4><ul>\r\n<li>requires the \'WP All Import - ACF Add-On Free\' plugin</li>\r\n<li>bug fix: free version loading could conflict with other plugins in some cases</li>\r\n</ul><h4>3.4.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: old repeater rows may not be removed in all cases</li>\r\n<li>bug fix: PHP notices</li>\r\n<li>bug fix: fatal error when loading Flexible Content layouts in some cases</li>\r\n</ul><h4>3.3.9</h4><ul>\r\n<li>improvement: support for importing files into gallery field</li>\r\n<li>improvement: support for Font Awesome field</li>\r\n<li>bug fix: uncaught type error</li>\r\n<li>bug fix: do not filter empty values in csv repeater</li>\r\n<li>bug fix: resolve error when importing clone fields in certain cases</li>\r\n<li>bug fix: PHP error on parsing the Link field</li>\r\n<li>bug fix: update only selected acf fields</li>\r\n<li>bug fix: miscellaneous PHP errors</li>\r\n<li>bug fix: acf gallery field undefined error</li>\r\n<li>bug fix: incorrect data format for Google Maps field</li>\r\n<li>bug fix: correctly save ACF fields to WooCommerce Customers</li>\r\n<li>bug fix: fatal error on PHP 8.2 for relationship and taxonomy fields</li>\r\n<li>bug fix: ACF fields from other post types can unexpectedly be shown in the dropdowns on the settings page</li>\r\n<li>bug fix: fatal error when $update_cache isn\'t an object</li>\r\n<li>bug fix: fatal error in some cases when extracting group data</li>\r\n<li>bug fix: wrong field names generated for clone fields in some cases</li>\r\n</ul><h4>3.3.8</h4><ul>\r\n    <li>bug fix: flexible content field not recognized</li>\r\n    <li>bug fix: clone field not recognized</li>\r\n    <li>bugfix: images and files downloaded twice in some cases</li>\r\n    <li>improvement: added \'wp_all_import_is_import_empty_acf_fields\' filter</li>\r\n    <li>improvement: resolve notices related to repeater fields</li>\r\n    <li>improvement: include subfields in the \'Choose which data to update\' selection dropdowns when using ACF v5</li>\r\n</ul><h4>3.3.7</h4>\r\n<ul>\r\n<li>bug fix: errors with repeater fields on PHP 8</li>\r\n<li>bug fix: gallery image names not properly parsed</li>\r\n<li>improvement: better autoloading of plugin files</li>\r\n</ul>\r\n<h4>3.3.6</h4>\r\n<ul>\r\n    <li>improvement: PHP 8 compatibility</li>\r\n    <li>bugfix: unable to import mapped ACF groups in some cases</li>\r\n    <li>bugfix: unable to import table field in fixed mode</li>\r\n    <li>bugfix: clone field not rendering correctly</li>\r\n    <li>bugfix: ACF fields not instantiated during cron import</li>\r\n</ul>\r\n<h4>3.3.5</h4>\r\n<ul>\r\n 	<li>bugfix: search for existing files didn\'t work in some cases</li>\r\n 	<li>bugfix: import gallery inside fixed repeater didn\'t work</li>\r\n 	<li>bugfix: ACF fields were loaded too early, some functions weren\'t available in the filters</li>\r\n 	<li>bugfix: local ACF groups weren\'t saved in import template</li>\r\n</ul>\r\n<h4>3.3.4</h4>\r\n<ul>\r\n 	<li>bugfix: ACF field groups not found in some cases</li>\r\n</ul>\r\n<h4>3.3.3</h4>\r\n<ul>\r\n 	<li>bugfix: ACF Repeater subfields not shown when configuring import</li>\r\n</ul>\r\n<h4>3.3.2</h4>\r\n<ul>\r\n 	<li>bug fix: acf groups visibility didn\'t work properly in some cases</li>\r\n 	<li>improvement: use acf built-in functions to get list of fields</li>\r\n</ul>\r\n<h4>3.3.1</h4>\r\n<ul>\r\n 	<li>improvement: enable ACF field developers to add support for WPAI to their field types</li>\r\n 	<li>bug fix: import repeater field generated with PHP didn\'t work</li>\r\n 	<li>bug fix: import ACF local fields didn\'t work in some cases</li>\r\n</ul>\r\n<h4>3.3.0</h4>\r\n<ul>\r\n 	<li>bug fix: Date picker used wrong format</li>\r\n 	<li>bug fix: Import template showing empty values for repeater fields</li>\r\n 	<li>bug fix: Link field inside fixed repeater field was not imported correctly</li>\r\n 	<li>bug fix: Nested taxonomy fields were not rendered correctly in import template</li>\r\n 	<li>bug fix: the ACF Field groups weren\'t chosen correctly when import bundle from WP All Export</li>\r\n</ul>\r\n<h4>3.2.9</h4>\r\n<ul>\r\n 	<li>improvement: add support for table field</li>\r\n 	<li>improvement: check post types when searching by ID for relationship fields</li>\r\n 	<li>bug fix: UI broken for True False field</li>\r\n 	<li>bug fix: \'Select value for all records\' not working for \'Taxonomy\' fields</li>\r\n</ul>\r\n<h4>3.2.8</h4>\r\n<ul>\r\n 	<li>improvement: compatibility with WordPress 5.5</li>\r\n 	<li>bug fix: import taxonomies inside repeater doesn\'t work in same cases</li>\r\n 	<li>bug fix: WYSIWYG field data prefixed with space</li>\r\n</ul>\r\n<h4>3.2.7</h4>\r\n<ul>\r\n 	<li>bug fix: Multiple Select field not imported correctly</li>\r\n</ul>\r\n<h4>3.2.6</h4>\r\n<ul>\r\n 	<li>improvement: add default zoom value for Google Maps field</li>\r\n 	<li>API: apply pmxi_acf_custom_field filter to taxonomy terms meta</li>\r\n 	<li>bug fix: unable to double click to insert XPath in some cases</li>\r\n 	<li>bug fix: unable to import WooCommerce customer ACF fields</li>\r\n 	<li>bug fix: select field with stylized UI not rendered properly</li>\r\n 	<li>bug fix: empty layouts for Flexible Content fields improperly imported</li>\r\n</ul>\r\n<h4>3.2.5</h4>\r\n<ul>\r\n 	<li>improvement: extend Google Maps field options</li>\r\n 	<li>improvement: save custom choice for radio button field</li>\r\n 	<li>bug fix: Google Maps field UI does not render properly</li>\r\n 	<li>bug fix: unable to import country field with multiple values</li>\r\n</ul>\r\n<h4>3.2.4</h4>\r\n<ul>\r\n 	<li>improvement: add support for Image Aspect Ratio Crop field</li>\r\n 	<li>bug fix: unable to add new images to gallery field</li>\r\n 	<li>bug fix: unable to add link field inside repeater</li>\r\n 	<li>bug fix: group field not rendering properly</li>\r\n</ul>\r\n<h4>3.2.3</h4>\r\n<ul>\r\n 	<li>bug fix: import gallery field inside repeater produced set of duplicate rows</li>\r\n 	<li>bug fix: import ACF field key was populated with field name instead of field key</li>\r\n</ul>\r\n<h4>3.2.2</h4>\r\n- Fixed import repeater field\r\n<h4>3.2.1</h4>\r\n<ul>\r\n 	<li>improvement: add support for country field - https://github.com/nlemoine/acf-country</li>\r\n 	<li>improvement: apply ACF filters when importing field values</li>\r\n 	<li>bug fix:search existing images by filename doesn\'t work correctly with galleries</li>\r\n 	<li>bug fix: $articleData argument missing in wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: taxonomy field for users not importing properly</li>\r\n</ul>\r\n<h4>3.2.0</h4>\r\n<ul>\r\n 	<li>improvement: added support for new ACF field: Star Rating</li>\r\n 	<li>bug fix: compatibility with ACF v5.7.11</li>\r\n 	<li>bug fix: compatibility with ACF v4.4.12</li>\r\n 	<li>bug fix: rendering select field choices</li>\r\n 	<li>bug fix: search for existing images option</li>\r\n 	<li>bug fix: rendering ACF groups</li>\r\n 	<li>bug fix: Google Map field - save lat and long as string instead of decimal value</li>\r\n 	<li>bug fix: import taxonomy field inside repeater in fixed mode</li>\r\n 	<li>bug fix: import empty checkbox field</li>\r\n 	<li>bug fix: import repeater in XML mode</li>\r\n</ul>\r\n<h4>3.1.9</h4>\r\n<ul>\r\n 	<li>bug fix: ACF groups visibility on import template screen</li>\r\n</ul>\r\n<h4>3.1.8</h4>\r\n<ul>\r\n 	<li>improvement: render only visible ACF field groups on import template screen</li>\r\n 	<li>improvement: added new field support - image_crop</li>\r\n 	<li>bug fix: import Relationship field</li>\r\n 	<li>bug fix: import taxonomy hierarchy inside Repeater</li>\r\n 	<li>bug fix: ignore empty rows for Repeater in csv mode</li>\r\n 	<li>bug fix: import checkbox using XPath</li>\r\n 	<li>bug fix: import post object field with multiple selection</li>\r\n 	<li>bug fix: import Repeater inside Repeater in csv mode</li>\r\n 	<li>bug fix: ignore empty rows option</li>\r\n 	<li>bug fix: detecting google map api key</li>\r\n 	<li>bug fix: date format for date picker field ACF 4.x</li>\r\n 	<li>bug fix: update only these fields for ACF 4.x</li>\r\n 	<li>bug fix: rendering local ACF fields defined in ACF 4.x syntax</li>\r\n</ul>\r\n<h4>3.1.7</h4>\r\n<ul>\r\n 	<li>bug fix: import nested repeaters in XML mode</li>\r\n 	<li>bug fix: \'Ignore empty rows\' doesn\'t ignore empty rows</li>\r\n 	<li>bug fix: repeater sub fields not saved in ACF 4.x</li>\r\n 	<li>bug fix: unable to set relationship fields when post type is not defined for related content</li>\r\n 	<li>bug fix: unable to import taxonomy fields inside repeater fields</li>\r\n</ul>\r\n<h4>3.1.6</h4>\r\n<ul>\r\n 	<li>improvement: added support for link field</li>\r\n 	<li>improvement: added support for Font Awesome Icon field</li>\r\n 	<li>improvement: added support for range field</li>\r\n 	<li>improvement: added support for button_group field</li>\r\n 	<li>improvement: render acf groups alphabetically</li>\r\n 	<li>bug fix: import post object filed based on acf post type settings</li>\r\n 	<li>bug fix: updating acf when update option disabled</li>\r\n 	<li>bug fix: added wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: rendering ACF local fields</li>\r\n 	<li>bug fix: import relationship field based on custom types in field settings</li>\r\n</ul>\r\n<h4>3.1.5</h4>\r\n<ul>\r\n 	<li>bug fix: import post object field</li>\r\n 	<li>bug fix: matching relationship posts</li>\r\n 	<li>bug fix: using google maps api key</li>\r\n 	<li>bug fix: import clone group field</li>\r\n 	<li>bug fix: date time picker format</li>\r\n 	<li>bug fix: import empty image field in repeater</li>\r\n</ul>\r\n<h4>3.1.4</h4>\r\n<ul>\r\n 	<li>improvement: performance optimization</li>\r\n 	<li>improvement: added support for Vimeo field type</li>\r\n 	<li>bug fix: search for existing files</li>\r\n 	<li>bug fix: import images into File field</li>\r\n 	<li>bug fix: import relationship inside repeater</li>\r\n</ul>\r\n<h4>3.1.3</h4>\r\n<ul>\r\n 	<li>improvement: added support for new ACF field \'Google Map Extended\'</li>\r\n 	<li>bug fix: import ACF repeater in fixed mode</li>\r\n 	<li>bug fix: saving ACF taxonomy import template</li>\r\n 	<li>bug fix: leave these ACF fields alone, update all other ACF fields</li>\r\n 	<li>bug fix: import ACF to taxonomies</li>\r\n 	<li>bug fix: saving ACF select field</li>\r\n</ul>\r\n<h4>3.1.2</h4>\r\n<ul>\r\n 	<li>improvement: compatibility with PHP 7.x</li>\r\n 	<li>improvement: new field type \'time picker\'</li>\r\n 	<li>improvement: new delimiter option for relationship fields</li>\r\n 	<li>bug fix: rendering repeater field inside flexible field in case when ACF configuration presented in functions.php file</li>\r\n 	<li>bug fix: import 0 value for number field inside repeater</li>\r\n</ul>\r\n<h4>3.1.1</h4>\r\n<ul>\r\n 	<li>improvement: support for clone field</li>\r\n 	<li>improvement: new option \'only append new images to the gallery\'</li>\r\n 	<li>improvement: new filter pmxi_acf_custom_field</li>\r\n 	<li>bug fix: flexible field JS conflict</li>\r\n 	<li>bug fix: search for existing image in media gallery</li>\r\n 	<li>bug fix: import ACF taxonomies to users</li>\r\n 	<li>bug fix: conflict between updating custom fields and ACF</li>\r\n 	<li>bug fix: acf grops duplicates</li>\r\n 	<li>bug fix: compatibility with php 7</li>\r\n 	<li>bug fix: import repeater in repeater for CSV mode</li>\r\n</ul>\r\n<h4>3.1.0</h4>\r\n<ul>\r\n 	<li>fixed ignore blank rows for fixed repeater mode</li>\r\n 	<li>fixed import taxonomy field</li>\r\n 	<li>fixed import multiple checkbox field in csv repeater mode</li>\r\n 	<li>added a \'Search through Media Library\' checkbox for each image field</li>\r\n 	<li>added geocode API settings to map field</li>\r\n</ul>\r\n<h4>3.0.9</h4>\r\n<ul>\r\n 	<li>fixed repeater field ( Variable mode XML )</li>\r\n</ul>\r\n<h4>3.0.8</h4>\r\n<ul>\r\n 	<li>fixed import taxonomy field</li>\r\n 	<li>fixed search for existing images is case when there are a few files with the same name in database</li>\r\n</ul>\r\n<h4>3.0.7</h4>\r\n<ul>\r\n 	<li>fixed import empty gallery field</li>\r\n</ul>\r\n<h4>3.0.6</h4>\r\n<ul>\r\n 	<li>added a separator option for gallery field</li>\r\n 	<li>fixed excessive update requests</li>\r\n</ul>\r\n<h4>3.0.5</h4>\r\n<ul>\r\n 	<li>fixed import field type file</li>\r\n 	<li>fixed loading import template</li>\r\n 	<li>fixed link to repeater field documentation</li>\r\n 	<li>fixed import relationship fields</li>\r\n</ul>\r\n<h4>3.0.4</h4>\r\n<ul>\r\n 	<li>fixed import mapped acf for 5.x version</li>\r\n 	<li>improved security</li>\r\n</ul>\r\n<h4>3.0.3</h4>\r\n<ul>\r\n 	<li>fixed import ACF for users</li>\r\n 	<li>fixed import image &amp; file fields ( searching image in attachments before download )</li>\r\n 	<li>added flexible content field</li>\r\n</ul>\r\n<h4>3.0.2</h4>\r\n<ul>\r\n 	<li>fixed conflict between repeater and taxonomy</li>\r\n 	<li>added support validated_field type</li>\r\n</ul>\r\n<h4>3.0.1</h4>\r\n<ul>\r\n 	<li>fixed call to non existing object property php error</li>\r\n 	<li>changed main plugin file name</li>\r\n</ul>\r\n<h4>3.0.0</h4>\r\n<ul>\r\n 	<li>New Advanced Custom Fields Add-On for WP All Import 4.0. Works with both ACF4 and ACF5/Pro. Learn more about WP All Import 4.0 at http://www.wpallimport.com/2014/11/introducing-wp-all-import-4-0/</li>\r\n</ul>\r\n<h4>2.0.1</h4>\r\n<ul>\r\n 	<li>Compatibility with ACF 5.0.0</li>\r\n</ul>\r\n<h4>1.0.0</h4>\r\n<ul>\r\n 	<li>fixed import images</li>\r\n 	<li>fixed session issue</li>\r\n 	<li>fixed data picker</li>\r\n</ul>\r\n<h4>0.9.7</h4>\r\n<ul>\r\n 	<li>fixed: php notices</li>\r\n 	<li>fixed: import taxonomies field</li>\r\n 	<li>fixed: import file field</li>\r\n 	<li>added: new option \"update only mapped ACF\"</li>\r\n 	<li>added: possibility to update repeater sub fields in re-import section</li>\r\n</ul>\r\n<h4>0.9.6</h4>\r\n<ul>\r\n 	<li>fixed: sanitizing file names</li>\r\n 	<li>fixed: load options template</li>\r\n 	<li>fixed: php warnings</li>\r\n</ul>\r\n<h4>0.9.5</h4>\r\n<ul>\r\n 	<li>fixed: php notices</li>\r\n 	<li>fixed: import repeater field</li>\r\n 	<li>fixed: js errors in taxonomies field</li>\r\n</ul>\";}s:7:\"banners\";a:2:{s:4:\"high\";s:0:\"\";s:3:\"low\";s:0:\"\";}s:18:\"custom_update_note\";s:0:\"\";s:19:\"update_note_version\";s:0:\"\";s:5:\"icons\";a:0:{}s:3:\"msg\";s:8:\"Success.\";s:7:\"package\";s:87:\"https://update.wpallimport.com/serve_package?package_id=2707178&version=4.0.1&license=0\";s:13:\"download_link\";s:87:\"https://update.wpallimport.com/serve_package?package_id=2707178&version=4.0.1&license=0\";s:6:\"tested\";s:5:\"6.9.1\";s:6:\"author\";s:6:\"Soflyy\";s:8:\"requires\";s:3:\"5.0\";s:12:\"requires_php\";s:3:\"7.4\";}','off'),
(24562,'_site_transient_update_plugins','O:8:\"stdClass\":5:{s:12:\"last_checked\";i:1771590966;s:8:\"response\";a:4:{s:35:\"insert-headers-and-footers/ihaf.php\";O:8:\"stdClass\":13:{s:2:\"id\";s:40:\"w.org/plugins/insert-headers-and-footers\";s:4:\"slug\";s:26:\"insert-headers-and-footers\";s:6:\"plugin\";s:35:\"insert-headers-and-footers/ihaf.php\";s:11:\"new_version\";s:5:\"2.3.4\";s:3:\"url\";s:57:\"https://wordpress.org/plugins/insert-headers-and-footers/\";s:7:\"package\";s:75:\"https://downloads.wordpress.org/plugin/insert-headers-and-footers.2.3.4.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:79:\"https://ps.w.org/insert-headers-and-footers/assets/icon-256x256.png?rev=2758516\";s:2:\"1x\";s:79:\"https://ps.w.org/insert-headers-and-footers/assets/icon-128x128.png?rev=2758516\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:82:\"https://ps.w.org/insert-headers-and-footers/assets/banner-1544x500.png?rev=2758516\";s:2:\"1x\";s:81:\"https://ps.w.org/insert-headers-and-footers/assets/banner-772x250.png?rev=2758516\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"5.0\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";s:3:\"7.0\";s:16:\"requires_plugins\";a:0:{}}s:24:\"wordpress-seo/wp-seo.php\";O:8:\"stdClass\":13:{s:2:\"id\";s:27:\"w.org/plugins/wordpress-seo\";s:4:\"slug\";s:13:\"wordpress-seo\";s:6:\"plugin\";s:24:\"wordpress-seo/wp-seo.php\";s:11:\"new_version\";s:4:\"27.0\";s:3:\"url\";s:44:\"https://wordpress.org/plugins/wordpress-seo/\";s:7:\"package\";s:61:\"https://downloads.wordpress.org/plugin/wordpress-seo.27.0.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:66:\"https://ps.w.org/wordpress-seo/assets/icon-256x256.gif?rev=3419908\";s:2:\"1x\";s:66:\"https://ps.w.org/wordpress-seo/assets/icon-128x128.gif?rev=3419908\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:69:\"https://ps.w.org/wordpress-seo/assets/banner-1544x500.png?rev=3257862\";s:2:\"1x\";s:68:\"https://ps.w.org/wordpress-seo/assets/banner-772x250.png?rev=3257862\";}s:11:\"banners_rtl\";a:2:{s:2:\"2x\";s:73:\"https://ps.w.org/wordpress-seo/assets/banner-1544x500-rtl.png?rev=3257862\";s:2:\"1x\";s:72:\"https://ps.w.org/wordpress-seo/assets/banner-772x250-rtl.png?rev=3257862\";}s:8:\"requires\";s:3:\"6.8\";s:6:\"tested\";s:5:\"6.9.1\";s:12:\"requires_php\";s:3:\"7.4\";s:16:\"requires_plugins\";a:0:{}}s:39:\"wpae-acf-add-on/wpae-acf-add-on-pro.php\";O:8:\"stdClass\":20:{s:11:\"new_version\";s:5:\"1.0.6\";s:14:\"stable_version\";s:5:\"1.0.6\";s:4:\"name\";s:21:\"ACF Export Add-On Pro\";s:4:\"slug\";s:15:\"wpae-acf-add-on\";s:6:\"plugin\";s:0:\"\";s:3:\"url\";s:72:\"https://www.wpallimport.com/downloads/acf-export-add-on-pro/?changelog=1\";s:12:\"last_updated\";s:19:\"2025-08-04 16:32:56\";s:8:\"homepage\";s:60:\"https://www.wpallimport.com/downloads/acf-export-add-on-pro/\";s:8:\"sections\";a:2:{s:11:\"description\";s:132:\"<p>Learn more at <a href=\"http://www.wpallimport.com/\" target=\"_blank\" rel=\"noopener noreferrer\">http://www.wpallimport.com/</a></p>\";s:9:\"changelog\";s:2020:\"<h4>1.0.6</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>improvement: check all location rules to identify what to display in the ACF section</li>\r\n<li>bug fix: fatal error when exporting user fields in some cases</li>\r\n<li>bug fix: jumbled UI when editing export fields using Brave browser</li>\r\n<li>bug fix: relationship field isn\'t exported correctly when limited to exactly 1 related post in ACF configuration</li>\r\n<li>bug fix: Gallery field is blank when return format is set to \'Image URL\'</li>\r\n<li>bug fix: select values are double serialized in some cases</li>\r\n<li>bug fix: repeater fields in blocks are not exported</li>\r\n<li>bug fix: fatal error when $update_cache isn\'t an object</li>\r\n<li>bug fix: fatal error related to ACF format_value calls</li>\r\n<li>bug fix: fatal error when exporting nested flexible content fields</li>\r\n<li>bug fix: export correct value when post field supports multiple values but only one is set</li>\r\n<li>bug fix: some \"location\" rules within register_field_group can cause an error</li>\r\n<li>bug fix: clone fields fail in some cases</li>\r\n<li>bug fix: nested repeaters fail in some cases</li>\r\n</ul><h4>1.0.5</h4><ul>\r\n<li>improvement: add support for locally defined ACF Blocks</li>\r\n<li>bug fix: resolve issue when exporting ACF Blocks</li>\r\n<li>bug fix: resolve issue when exporting ACF multiple select fields</li>\r\n<li>bug fix: PHP 8 error with Flexible Content Fields</li>\r\n<li>bug fix: resolve issue with changelog showing incorrect information</li>\r\n</ul><h4>1.0.4</h4><ul>\r\n<li>bug fix: ACF link field isn\'t exported correctly if \'Link URL\' is set as the return value</li>\r\n</ul><h4>1.0.3</h4>\r\n<ul>\r\n 	<li>improvement: decrease frequency of plugin update checks</li>\r\n 	<li>improvement: initial PHP 8 support</li>\r\n</ul>\r\n<h4>1.0.2</h4>\r\n<ul>\r\n 	<li>cleanup: remove plugins page notice</li>\r\n</ul>\r\n<h4>1.0.1</h4>\r\n<ul>\r\n 	<li>improvement: enable sslverify</li>\r\n</ul>\r\n<h4>1.0.0</h4>\r\n<ul>\r\n 	<li>Initial release</li>\r\n</ul>\";}s:7:\"banners\";a:2:{s:4:\"high\";s:0:\"\";s:3:\"low\";s:0:\"\";}s:18:\"custom_update_note\";s:0:\"\";s:19:\"update_note_version\";s:0:\"\";s:5:\"icons\";a:0:{}s:3:\"msg\";s:8:\"Success.\";s:7:\"package\";s:87:\"https://update.wpallimport.com/serve_package?package_id=4203451&version=1.0.6&license=0\";s:13:\"download_link\";s:87:\"https://update.wpallimport.com/serve_package?package_id=4203451&version=1.0.6&license=0\";s:6:\"tested\";s:5:\"6.9.1\";s:6:\"author\";s:6:\"Soflyy\";s:8:\"requires\";s:3:\"5.0\";s:12:\"requires_php\";s:3:\"7.4\";}s:35:\"wpai-acf-add-on/wpai-acf-add-on.php\";O:8:\"stdClass\":20:{s:11:\"new_version\";s:5:\"4.0.1\";s:14:\"stable_version\";s:5:\"4.0.1\";s:4:\"name\";s:10:\"ACF Add-On\";s:4:\"slug\";s:15:\"wpai-acf-add-on\";s:6:\"plugin\";s:0:\"\";s:3:\"url\";s:68:\"https://www.wpallimport.com/downloads/acf-import-add-on/?changelog=1\";s:12:\"last_updated\";s:19:\"2025-09-16 23:07:46\";s:8:\"homepage\";s:56:\"https://www.wpallimport.com/downloads/acf-import-add-on/\";s:8:\"sections\";a:2:{s:11:\"description\";s:132:\"<p>Learn more at <a href=\"http://www.wpallimport.com/\" target=\"_blank\" rel=\"noopener noreferrer\">http://www.wpallimport.com/</a></p>\";s:9:\"changelog\";s:13586:\"<h4>4.0.1</h4><ul>\r\n<li>requires the \'WP All Import - ACF Add-On Free\' plugin</li>\r\n<li>bug fix: free version loading could conflict with other plugins in some cases</li>\r\n</ul><h4>3.4.0</h4><ul>\r\n<li>minimum WordPress version: 5.0</li>\r\n<li>minimum PHP version: 7.4</li>\r\n<li>bug fix: old repeater rows may not be removed in all cases</li>\r\n<li>bug fix: PHP notices</li>\r\n<li>bug fix: fatal error when loading Flexible Content layouts in some cases</li>\r\n</ul><h4>3.3.9</h4><ul>\r\n<li>improvement: support for importing files into gallery field</li>\r\n<li>improvement: support for Font Awesome field</li>\r\n<li>bug fix: uncaught type error</li>\r\n<li>bug fix: do not filter empty values in csv repeater</li>\r\n<li>bug fix: resolve error when importing clone fields in certain cases</li>\r\n<li>bug fix: PHP error on parsing the Link field</li>\r\n<li>bug fix: update only selected acf fields</li>\r\n<li>bug fix: miscellaneous PHP errors</li>\r\n<li>bug fix: acf gallery field undefined error</li>\r\n<li>bug fix: incorrect data format for Google Maps field</li>\r\n<li>bug fix: correctly save ACF fields to WooCommerce Customers</li>\r\n<li>bug fix: fatal error on PHP 8.2 for relationship and taxonomy fields</li>\r\n<li>bug fix: ACF fields from other post types can unexpectedly be shown in the dropdowns on the settings page</li>\r\n<li>bug fix: fatal error when $update_cache isn\'t an object</li>\r\n<li>bug fix: fatal error in some cases when extracting group data</li>\r\n<li>bug fix: wrong field names generated for clone fields in some cases</li>\r\n</ul><h4>3.3.8</h4><ul>\r\n    <li>bug fix: flexible content field not recognized</li>\r\n    <li>bug fix: clone field not recognized</li>\r\n    <li>bugfix: images and files downloaded twice in some cases</li>\r\n    <li>improvement: added \'wp_all_import_is_import_empty_acf_fields\' filter</li>\r\n    <li>improvement: resolve notices related to repeater fields</li>\r\n    <li>improvement: include subfields in the \'Choose which data to update\' selection dropdowns when using ACF v5</li>\r\n</ul><h4>3.3.7</h4>\r\n<ul>\r\n<li>bug fix: errors with repeater fields on PHP 8</li>\r\n<li>bug fix: gallery image names not properly parsed</li>\r\n<li>improvement: better autoloading of plugin files</li>\r\n</ul>\r\n<h4>3.3.6</h4>\r\n<ul>\r\n    <li>improvement: PHP 8 compatibility</li>\r\n    <li>bugfix: unable to import mapped ACF groups in some cases</li>\r\n    <li>bugfix: unable to import table field in fixed mode</li>\r\n    <li>bugfix: clone field not rendering correctly</li>\r\n    <li>bugfix: ACF fields not instantiated during cron import</li>\r\n</ul>\r\n<h4>3.3.5</h4>\r\n<ul>\r\n 	<li>bugfix: search for existing files didn\'t work in some cases</li>\r\n 	<li>bugfix: import gallery inside fixed repeater didn\'t work</li>\r\n 	<li>bugfix: ACF fields were loaded too early, some functions weren\'t available in the filters</li>\r\n 	<li>bugfix: local ACF groups weren\'t saved in import template</li>\r\n</ul>\r\n<h4>3.3.4</h4>\r\n<ul>\r\n 	<li>bugfix: ACF field groups not found in some cases</li>\r\n</ul>\r\n<h4>3.3.3</h4>\r\n<ul>\r\n 	<li>bugfix: ACF Repeater subfields not shown when configuring import</li>\r\n</ul>\r\n<h4>3.3.2</h4>\r\n<ul>\r\n 	<li>bug fix: acf groups visibility didn\'t work properly in some cases</li>\r\n 	<li>improvement: use acf built-in functions to get list of fields</li>\r\n</ul>\r\n<h4>3.3.1</h4>\r\n<ul>\r\n 	<li>improvement: enable ACF field developers to add support for WPAI to their field types</li>\r\n 	<li>bug fix: import repeater field generated with PHP didn\'t work</li>\r\n 	<li>bug fix: import ACF local fields didn\'t work in some cases</li>\r\n</ul>\r\n<h4>3.3.0</h4>\r\n<ul>\r\n 	<li>bug fix: Date picker used wrong format</li>\r\n 	<li>bug fix: Import template showing empty values for repeater fields</li>\r\n 	<li>bug fix: Link field inside fixed repeater field was not imported correctly</li>\r\n 	<li>bug fix: Nested taxonomy fields were not rendered correctly in import template</li>\r\n 	<li>bug fix: the ACF Field groups weren\'t chosen correctly when import bundle from WP All Export</li>\r\n</ul>\r\n<h4>3.2.9</h4>\r\n<ul>\r\n 	<li>improvement: add support for table field</li>\r\n 	<li>improvement: check post types when searching by ID for relationship fields</li>\r\n 	<li>bug fix: UI broken for True False field</li>\r\n 	<li>bug fix: \'Select value for all records\' not working for \'Taxonomy\' fields</li>\r\n</ul>\r\n<h4>3.2.8</h4>\r\n<ul>\r\n 	<li>improvement: compatibility with WordPress 5.5</li>\r\n 	<li>bug fix: import taxonomies inside repeater doesn\'t work in same cases</li>\r\n 	<li>bug fix: WYSIWYG field data prefixed with space</li>\r\n</ul>\r\n<h4>3.2.7</h4>\r\n<ul>\r\n 	<li>bug fix: Multiple Select field not imported correctly</li>\r\n</ul>\r\n<h4>3.2.6</h4>\r\n<ul>\r\n 	<li>improvement: add default zoom value for Google Maps field</li>\r\n 	<li>API: apply pmxi_acf_custom_field filter to taxonomy terms meta</li>\r\n 	<li>bug fix: unable to double click to insert XPath in some cases</li>\r\n 	<li>bug fix: unable to import WooCommerce customer ACF fields</li>\r\n 	<li>bug fix: select field with stylized UI not rendered properly</li>\r\n 	<li>bug fix: empty layouts for Flexible Content fields improperly imported</li>\r\n</ul>\r\n<h4>3.2.5</h4>\r\n<ul>\r\n 	<li>improvement: extend Google Maps field options</li>\r\n 	<li>improvement: save custom choice for radio button field</li>\r\n 	<li>bug fix: Google Maps field UI does not render properly</li>\r\n 	<li>bug fix: unable to import country field with multiple values</li>\r\n</ul>\r\n<h4>3.2.4</h4>\r\n<ul>\r\n 	<li>improvement: add support for Image Aspect Ratio Crop field</li>\r\n 	<li>bug fix: unable to add new images to gallery field</li>\r\n 	<li>bug fix: unable to add link field inside repeater</li>\r\n 	<li>bug fix: group field not rendering properly</li>\r\n</ul>\r\n<h4>3.2.3</h4>\r\n<ul>\r\n 	<li>bug fix: import gallery field inside repeater produced set of duplicate rows</li>\r\n 	<li>bug fix: import ACF field key was populated with field name instead of field key</li>\r\n</ul>\r\n<h4>3.2.2</h4>\r\n- Fixed import repeater field\r\n<h4>3.2.1</h4>\r\n<ul>\r\n 	<li>improvement: add support for country field - https://github.com/nlemoine/acf-country</li>\r\n 	<li>improvement: apply ACF filters when importing field values</li>\r\n 	<li>bug fix:search existing images by filename doesn\'t work correctly with galleries</li>\r\n 	<li>bug fix: $articleData argument missing in wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: taxonomy field for users not importing properly</li>\r\n</ul>\r\n<h4>3.2.0</h4>\r\n<ul>\r\n 	<li>improvement: added support for new ACF field: Star Rating</li>\r\n 	<li>bug fix: compatibility with ACF v5.7.11</li>\r\n 	<li>bug fix: compatibility with ACF v4.4.12</li>\r\n 	<li>bug fix: rendering select field choices</li>\r\n 	<li>bug fix: search for existing images option</li>\r\n 	<li>bug fix: rendering ACF groups</li>\r\n 	<li>bug fix: Google Map field - save lat and long as string instead of decimal value</li>\r\n 	<li>bug fix: import taxonomy field inside repeater in fixed mode</li>\r\n 	<li>bug fix: import empty checkbox field</li>\r\n 	<li>bug fix: import repeater in XML mode</li>\r\n</ul>\r\n<h4>3.1.9</h4>\r\n<ul>\r\n 	<li>bug fix: ACF groups visibility on import template screen</li>\r\n</ul>\r\n<h4>3.1.8</h4>\r\n<ul>\r\n 	<li>improvement: render only visible ACF field groups on import template screen</li>\r\n 	<li>improvement: added new field support - image_crop</li>\r\n 	<li>bug fix: import Relationship field</li>\r\n 	<li>bug fix: import taxonomy hierarchy inside Repeater</li>\r\n 	<li>bug fix: ignore empty rows for Repeater in csv mode</li>\r\n 	<li>bug fix: import checkbox using XPath</li>\r\n 	<li>bug fix: import post object field with multiple selection</li>\r\n 	<li>bug fix: import Repeater inside Repeater in csv mode</li>\r\n 	<li>bug fix: ignore empty rows option</li>\r\n 	<li>bug fix: detecting google map api key</li>\r\n 	<li>bug fix: date format for date picker field ACF 4.x</li>\r\n 	<li>bug fix: update only these fields for ACF 4.x</li>\r\n 	<li>bug fix: rendering local ACF fields defined in ACF 4.x syntax</li>\r\n</ul>\r\n<h4>3.1.7</h4>\r\n<ul>\r\n 	<li>bug fix: import nested repeaters in XML mode</li>\r\n 	<li>bug fix: \'Ignore empty rows\' doesn\'t ignore empty rows</li>\r\n 	<li>bug fix: repeater sub fields not saved in ACF 4.x</li>\r\n 	<li>bug fix: unable to set relationship fields when post type is not defined for related content</li>\r\n 	<li>bug fix: unable to import taxonomy fields inside repeater fields</li>\r\n</ul>\r\n<h4>3.1.6</h4>\r\n<ul>\r\n 	<li>improvement: added support for link field</li>\r\n 	<li>improvement: added support for Font Awesome Icon field</li>\r\n 	<li>improvement: added support for range field</li>\r\n 	<li>improvement: added support for button_group field</li>\r\n 	<li>improvement: render acf groups alphabetically</li>\r\n 	<li>bug fix: import post object filed based on acf post type settings</li>\r\n 	<li>bug fix: updating acf when update option disabled</li>\r\n 	<li>bug fix: added wp_all_import_images_uploads_dir filter</li>\r\n 	<li>bug fix: rendering ACF local fields</li>\r\n 	<li>bug fix: import relationship field based on custom types in field settings</li>\r\n</ul>\r\n<h4>3.1.5</h4>\r\n<ul>\r\n 	<li>bug fix: import post object field</li>\r\n 	<li>bug fix: matching relationship posts</li>\r\n 	<li>bug fix: using google maps api key</li>\r\n 	<li>bug fix: import clone group field</li>\r\n 	<li>bug fix: date time picker format</li>\r\n 	<li>bug fix: import empty image field in repeater</li>\r\n</ul>\r\n<h4>3.1.4</h4>\r\n<ul>\r\n 	<li>improvement: performance optimization</li>\r\n 	<li>improvement: added support for Vimeo field type</li>\r\n 	<li>bug fix: search for existing files</li>\r\n 	<li>bug fix: import images into File field</li>\r\n 	<li>bug fix: import relationship inside repeater</li>\r\n</ul>\r\n<h4>3.1.3</h4>\r\n<ul>\r\n 	<li>improvement: added support for new ACF field \'Google Map Extended\'</li>\r\n 	<li>bug fix: import ACF repeater in fixed mode</li>\r\n 	<li>bug fix: saving ACF taxonomy import template</li>\r\n 	<li>bug fix: leave these ACF fields alone, update all other ACF fields</li>\r\n 	<li>bug fix: import ACF to taxonomies</li>\r\n 	<li>bug fix: saving ACF select field</li>\r\n</ul>\r\n<h4>3.1.2</h4>\r\n<ul>\r\n 	<li>improvement: compatibility with PHP 7.x</li>\r\n 	<li>improvement: new field type \'time picker\'</li>\r\n 	<li>improvement: new delimiter option for relationship fields</li>\r\n 	<li>bug fix: rendering repeater field inside flexible field in case when ACF configuration presented in functions.php file</li>\r\n 	<li>bug fix: import 0 value for number field inside repeater</li>\r\n</ul>\r\n<h4>3.1.1</h4>\r\n<ul>\r\n 	<li>improvement: support for clone field</li>\r\n 	<li>improvement: new option \'only append new images to the gallery\'</li>\r\n 	<li>improvement: new filter pmxi_acf_custom_field</li>\r\n 	<li>bug fix: flexible field JS conflict</li>\r\n 	<li>bug fix: search for existing image in media gallery</li>\r\n 	<li>bug fix: import ACF taxonomies to users</li>\r\n 	<li>bug fix: conflict between updating custom fields and ACF</li>\r\n 	<li>bug fix: acf grops duplicates</li>\r\n 	<li>bug fix: compatibility with php 7</li>\r\n 	<li>bug fix: import repeater in repeater for CSV mode</li>\r\n</ul>\r\n<h4>3.1.0</h4>\r\n<ul>\r\n 	<li>fixed ignore blank rows for fixed repeater mode</li>\r\n 	<li>fixed import taxonomy field</li>\r\n 	<li>fixed import multiple checkbox field in csv repeater mode</li>\r\n 	<li>added a \'Search through Media Library\' checkbox for each image field</li>\r\n 	<li>added geocode API settings to map field</li>\r\n</ul>\r\n<h4>3.0.9</h4>\r\n<ul>\r\n 	<li>fixed repeater field ( Variable mode XML )</li>\r\n</ul>\r\n<h4>3.0.8</h4>\r\n<ul>\r\n 	<li>fixed import taxonomy field</li>\r\n 	<li>fixed search for existing images is case when there are a few files with the same name in database</li>\r\n</ul>\r\n<h4>3.0.7</h4>\r\n<ul>\r\n 	<li>fixed import empty gallery field</li>\r\n</ul>\r\n<h4>3.0.6</h4>\r\n<ul>\r\n 	<li>added a separator option for gallery field</li>\r\n 	<li>fixed excessive update requests</li>\r\n</ul>\r\n<h4>3.0.5</h4>\r\n<ul>\r\n 	<li>fixed import field type file</li>\r\n 	<li>fixed loading import template</li>\r\n 	<li>fixed link to repeater field documentation</li>\r\n 	<li>fixed import relationship fields</li>\r\n</ul>\r\n<h4>3.0.4</h4>\r\n<ul>\r\n 	<li>fixed import mapped acf for 5.x version</li>\r\n 	<li>improved security</li>\r\n</ul>\r\n<h4>3.0.3</h4>\r\n<ul>\r\n 	<li>fixed import ACF for users</li>\r\n 	<li>fixed import image &amp; file fields ( searching image in attachments before download )</li>\r\n 	<li>added flexible content field</li>\r\n</ul>\r\n<h4>3.0.2</h4>\r\n<ul>\r\n 	<li>fixed conflict between repeater and taxonomy</li>\r\n 	<li>added support validated_field type</li>\r\n</ul>\r\n<h4>3.0.1</h4>\r\n<ul>\r\n 	<li>fixed call to non existing object property php error</li>\r\n 	<li>changed main plugin file name</li>\r\n</ul>\r\n<h4>3.0.0</h4>\r\n<ul>\r\n 	<li>New Advanced Custom Fields Add-On for WP All Import 4.0. Works with both ACF4 and ACF5/Pro. Learn more about WP All Import 4.0 at http://www.wpallimport.com/2014/11/introducing-wp-all-import-4-0/</li>\r\n</ul>\r\n<h4>2.0.1</h4>\r\n<ul>\r\n 	<li>Compatibility with ACF 5.0.0</li>\r\n</ul>\r\n<h4>1.0.0</h4>\r\n<ul>\r\n 	<li>fixed import images</li>\r\n 	<li>fixed session issue</li>\r\n 	<li>fixed data picker</li>\r\n</ul>\r\n<h4>0.9.7</h4>\r\n<ul>\r\n 	<li>fixed: php notices</li>\r\n 	<li>fixed: import taxonomies field</li>\r\n 	<li>fixed: import file field</li>\r\n 	<li>added: new option \"update only mapped ACF\"</li>\r\n 	<li>added: possibility to update repeater sub fields in re-import section</li>\r\n</ul>\r\n<h4>0.9.6</h4>\r\n<ul>\r\n 	<li>fixed: sanitizing file names</li>\r\n 	<li>fixed: load options template</li>\r\n 	<li>fixed: php warnings</li>\r\n</ul>\r\n<h4>0.9.5</h4>\r\n<ul>\r\n 	<li>fixed: php notices</li>\r\n 	<li>fixed: import repeater field</li>\r\n 	<li>fixed: js errors in taxonomies field</li>\r\n</ul>\";}s:7:\"banners\";a:2:{s:4:\"high\";s:0:\"\";s:3:\"low\";s:0:\"\";}s:18:\"custom_update_note\";s:0:\"\";s:19:\"update_note_version\";s:0:\"\";s:5:\"icons\";a:0:{}s:3:\"msg\";s:8:\"Success.\";s:7:\"package\";s:87:\"https://update.wpallimport.com/serve_package?package_id=2707178&version=4.0.1&license=0\";s:13:\"download_link\";s:87:\"https://update.wpallimport.com/serve_package?package_id=2707178&version=4.0.1&license=0\";s:6:\"tested\";s:5:\"6.9.1\";s:6:\"author\";s:6:\"Soflyy\";s:8:\"requires\";s:3:\"5.0\";s:12:\"requires_php\";s:3:\"7.4\";}}s:12:\"translations\";a:0:{}s:9:\"no_update\";a:12:{s:19:\"akismet/akismet.php\";O:8:\"stdClass\":10:{s:2:\"id\";s:21:\"w.org/plugins/akismet\";s:4:\"slug\";s:7:\"akismet\";s:6:\"plugin\";s:19:\"akismet/akismet.php\";s:11:\"new_version\";s:3:\"5.6\";s:3:\"url\";s:38:\"https://wordpress.org/plugins/akismet/\";s:7:\"package\";s:54:\"https://downloads.wordpress.org/plugin/akismet.5.6.zip\";s:5:\"icons\";a:2:{s:2:\"2x\";s:60:\"https://ps.w.org/akismet/assets/icon-256x256.png?rev=2818463\";s:2:\"1x\";s:60:\"https://ps.w.org/akismet/assets/icon-128x128.png?rev=2818463\";}s:7:\"banners\";a:2:{s:2:\"2x\";s:63:\"https://ps.w.org/akismet/assets/banner-1544x500.png?rev=2900731\";s:2:\"1x\";s:62:\"https://ps.w.org/akismet/assets/banner-772x250.png?rev=2900731\";}s:11:\"banners_rtl\";a:0:{}s:8:\"requires\";s:3:\"5.8\";}s:51:\"all-in-one-wp-migration/all-in-one-wp-migr