(5019,230,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n  \r\n  <div class=\"instrucciones\">\r\n    ???? ÂĄHola pequeĂ±o matemĂĄtico! Vamos a aprender a contar del 1 al 5. \r\n    Observa bien, cuenta con tus deditos y completa todas las actividades. ÂĄTĂș puedes hacerlo!\r\n  </div>\r\n\r\n  <!-- ========================================= -->\r\n  <!-- BLOQUE 1: PREGUNTAS SIMPLES (2 ejercicios) -->\r\n  <!-- ========================================= -->\r\n  \r\n  <div class=\"contenedor-preguntas\">\r\n\r\n    <!-- Ejercicio 1: Contar objetos visuales -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <div class=\"pregunta\">1. ÂżCuĂĄntas manzanas hay en el ĂĄrbol?</div>\r\n      <div class=\"visual\">???? ???? ????</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 2: Contar animales -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"5\">\r\n      <div class=\"pregunta\">2. Cuenta los pollitos amarillos</div>\r\n      <div class=\"visual\">???? ???? ???? ???? ????</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n        <button class=\"opcion-btn\" data-valor=\"6\">6</button>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- ========================================= -->\r\n  <!-- BLOQUE 2: DRAG & DROP (2 ejercicios) -->\r\n  <!-- ========================================= -->\r\n\r\n  <!-- Ejercicio 3: Clasificar por cantidad -->\r\n  <div class=\"ejercicio-dragdrop\">\r\n    <div class=\"pregunta\">3. Arrastra cada grupo de estrellas a su nĂșmero</div>\r\n    \r\n    <div class=\"dragdrop-container\">\r\n      <!-- Item