(5039,231,'_contenido_ficha_html','field_contenido_ficha_html'),
(5040,231,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n\r\n  <div class=\"instrucciones\">\r\n    ???? ÂĄHola pequeĂ±o matemĂĄtico! Vamos a contar y jugar con el nĂșmero 4.\r\n    Observa, elige, arrastra, escribe, busca y traza. ÂĄTĂș puedes!\r\n  </div>\r\n\r\n  <div class=\"contenedor-preguntas\">\r\n\r\n    <!-- 1) PREGUNTA SIMPLE -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4\">\r\n      <div class=\"pregunta\">1. ÂżCuĂĄntas estrellas ves?</div>\r\n      <div class=\"visual\">â­ â­ â­ â­</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 2) PREGUNTA SIMPLE -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"2\">\r\n      <div class=\"pregunta\">2. ÂżCuĂĄntos globos hay?</div>\r\n      <div class=\"visual\">???? ????</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 3) FILL BLANKS -->\r\n    <div class=\"ejercicio-fillblanks\">\r\n      <div class=\"pregunta-fillblanks\">3. Escribe el nĂșmero correcto</div>\r\n      <div class=\"fillblanks-texto\">\r\n        ???? ???? ???? ???? â Hay <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"4\" maxlength=\"1\"> manzanas.\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 4) FILL BLANKS -->\r\n    <div class=\"ejercicio-fillblanks\">\r\n      <div class=\"pregunta-fillblanks\">4. Completa la frase</div>\r\n      <div class=\"fillblanks-texto\">\r\n        Veo <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"3\" maxlength=\"1\"> perros ????????????.\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 5) DRAG & DROP -->\r\n    <div class=\"ejercicio-dragdrop\">\r\n      <div class=\"pregunta\">5. Arrastra cada grupo al nĂșmero correcto</div>\r\n      <div class=\"dragdrop-container\">\r\n        <div class=\"dragdrop-items\">\r\n          <div class=\"dragdrop-items-title\">Grupos</div>\r\n          <div class=\"dragdrop-items-grid\">\r\n            <div class=\"dragdrop-item\" data-valor=\"1\">â­</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"2\">â­â­</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"3\">â­â­â­</div>\r\n          </div>\r\n        </div>\r\n        <div class=\"dragdrop-zones\">\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"1\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 1</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"2\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 2</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"3\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 3</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 6) MEMORY -->\r\n    <div class=\"ejercicio-memory\" data-pares=\"3\">\r\n      <div class=\"pregunta-memory\">6. Encuentra las parejas</div>\r\n\r\n      <div class=\"memory-stats\">\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Movimientos:</span> <span class=\"memory-moves\"><strong>0</strong></span></div>\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Parejas:</span> <span class=\"memory-pairs\"><strong>0/3</strong></span></div>\r\n      </div>\r\n\r\n      <div class=\"memory-grid\">\r\n        <div class=\"memory-card\" data-pair=\"4\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">4</div></div>\r\n        <div class=\"memory-card\" data-pair=\"4\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">4</div></div>\r\n        <div class=\"memory-card\" data-pair=\"â­\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">â­</div></div>\r\n        <div class=\"memory-card\" data-pair=\"â­\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">â­</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n      </div>\r\n\r\n      <div class=\"memory-actions\">\r\n        <button class=\"btn-reiniciar-memory\">Reiniciar</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 7) WORDSEARCH -->\r\n    <div class=\"ejercicio-wordsearch\">\r\n      <div class=\"pregunta-wordsearch\">7. Busca la palabra: CUATRO</div>\r\n      <div class=\"wordsearch-container\">\r\n        <div class=\"wordsearch-grid\">\r\n          <table class=\"wordsearch-table\" data-words=\'[\"CUATRO\"]\'>\r\n            <tr><td class=\"wordsearch-cell\">C</td><td class=\"wordsearch-cell\">U</td><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">T</td><td class=\"wordsearch-cell\">R</td><td class=\"wordsearch-cell\">O</td></tr>\r\n            <tr><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">B</td><td class=\"wordsearch-cell\">C</td><td class=\"wordsearch-cell\">D</td><td class=\"wordsearch-cell\">E</td><td class=\"wordsearch-cell\">F</td></tr>\r\n            <tr><td class=\"wordsearch-cell\">G</td><td class=\"wordsearch-cell\">H</td><td class=\"wordsearch-cell\">I</td><td class=\"wordsearch-cell\">J</td><td class=\"wordsearch-cell\">K</td><td class=\"wordsearch-cell\">L</td></tr>\r\n            <tr><td class=\"wordsearch-cell\">M</td><td class=\"wordsearch-cell\">N</td><td class=\"wordsearch-cell\">O</td><td class=\"wordsearch-cell\">P</td><td class=\"wordsearch-cell\">Q</td><td class=\"wordsearch-cell\">R</td></tr>\r\n          </table>\r\n        </div>\r\n        <div class=\"wordsearch-words\">\r\n          <div class=\"wordsearch-words-title\">Palabras</div>\r\n          <div class=\"wordsearch-words-list\">\r\n            <span class=\"word-item\">CUATRO</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 8) TRAZO -->\r\n    <div class=\"ejercicio-trazo\">\r\n      <div class=\"pregunta-trazo\">8. Traza el nĂșmero 4</div>\r\n      <div class=\"trazo-canvas-container\">\r\n        <span class=\"trazo-guia\">4</span>\r\n        <canvas width=\"320\" height=\"200\"></canvas>\r\n      </div>\r\n      <div class=\"trazo-actions\">\r\n        <button class=\"btn-borrar-trazo\">Borrar</button>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <!-- BOTONES Y FEEDBACK -->\r\n  <div class=\"acciones\">\r\n    <button class=\"btn-comprobar\">â ÂĄYa terminĂ©! Comprobar respuestas</button>\r\n    <button class=\"btn-descargar-pdf\">???? Descargar PDF</button>\r\n  </div>\r\n\r\n  <div class=\"feedback\" style=\"display:none;\"></div>\r\n\r\n</div>\r\n\r\n\r\n'),
