(5060,232,'_contenido_ficha_html','field_contenido_ficha_html'),
(5061,232,'contenido_ficha_html','<!-- ================================================================\n     FICHA MIXTA COMPLETA - LOS 4 MODULOS\n     ================================================================ -->\n\n<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">&iexcl;Hola peque&ntilde;o matem&aacute;tico! Hoy vamos a practicar los n&uacute;meros del 1 al 4 con ejercicios divertidos. &iexcl;Empezamos!</div>\n\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"5\">\n      <div class=\"pregunta\">1. &iquest;Cu&aacute;ntos dedos ves en la mano?</div>\n      <div class=\"visual\">&#9995;</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"2\">\n      <div class=\"pregunta\">2. &iquest;Cu&aacute;ntas manzanas hay?</div>\n      <div class=\"visual\">&#127822; &#127822;</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\n      <div class=\"pregunta\">3. &iquest;Cu&aacute;ntos corazones ves?</div>\n      <div class=\"visual\">&#10084;&#65039; &#10084;&#65039; &#10084;&#65039;</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4\">\n      <div class=\"pregunta\">4. &iquest;Cu&aacute;ntas estrellas brillan?</div>\n      <div class=\"visual\">&#9733; &#9733; &#9733; &#9733;</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ejercicio-trazo\">\n    <div class=\"pregunta-trazo\">Repasa el n&uacute;mero 3 con tu dedo o el rat&oacute;n</div>\n    <div class=\"trazo-canvas-container\">\n      <div class=\"trazo-guia\">3</div>\n      <canvas width=\"600\" height=\"300\"></canvas>\n    </div>\n    <div class=\"trazo-actions\">\n      <button class=\"btn-borrar-trazo\">Borrar</button>\n    </div>\n  </div>\n\n  <div class=\"ejercicio-dragdrop\">\n    <div class=\"pregunta\">Arrastra cada n&uacute;mero a su grupo: &iquest;es peque&ntilde;o (1-2) o grande (3-4)?</div>\n    <div class=\"dragdrop-container\">\n      <div class=\"dragdrop-items\">\n        <div class=\"dragdrop-items-title\">N&uacute;meros</div>\n        <div class=\"dragdrop-items-grid\">\n          <div class=\"dragdrop-item\" data-valor=\"1\">1</div>\n          <div class=\"dragdrop-item\" data-valor=\"3\">3</div>\n          <div class=\"dragdrop-item\" data-valor=\"2\">2</div>\n          <div class=\"dragdrop-item\" data-valor=\"4\">4</div>\n        </div>\n      </div>\n\n      <div class=\"dragdrop-zones\">\n        <div class=\"dragdrop-zone\" data-respuesta-correcta=\"1,2\">\n          <div class=\"dragdrop-zone-title\">N&uacute;meros peque&ntilde;os (1-2)</div>\n          <div class=\"dragdrop-zone-content\"></div>\n        </div>\n        <div class=\"dragdrop-zone\" data-respuesta-correcta=\"3,4\">\n          <div class=\"dragdrop-zone-title\">N&uacute;meros grandes (3-4)</div>\n          <div class=\"dragdrop-zone-content\"></div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"ejercicio-memory\" data-pares=\"4\">\n    <div class=\"pregunta-memory\">Encuentra las parejas: n&uacute;mero con su cantidad de estrellas</div>\n    <div class=\"memory-grid\">\n      <div class=\"memory-card\" data-pair=\"par1\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">1</div>\n      </div>\n      <div class=\"memory-card\" data-pair=\"par1\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">&#9733;</div>\n      </div>\n\n      <div class=\"memory-card\" data-pair=\"par2\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">2</div>\n      </div>\n      <div class=\"memory-card\" data-pair=\"par2\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">&#9733; &#9733;</div>\n      </div>\n\n      <div class=\"memory-card\" data-pair=\"par3\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">3</div>\n      </div>\n      <div class=\"memory-card\" data-pair=\"par3\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">&#9733; &#9733; &#9733;</div>\n      </div>\n\n      <div class=\"memory-card\" data-pair=\"par4\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">4</div>\n      </div>\n      <div class=\"memory-card\" data-pair=\"par4\">\n        <div class=\"memory-card-front\">?</div>\n        <div class=\"memory-card-back\">&#9733; &#9733; &#9733; &#9733;</div>\n      </div>\n    </div>\n\n    <div class=\"memory-stats\">\n      <span class=\"memory-moves\">Movimientos: <strong>0</strong></span>\n      <span class=\"memory-pairs\">Parejas: <strong>0/4</strong></span>\n    </div>\n\n    <div class=\"memory-actions\">\n      <button class=\"btn-reiniciar-memory\">Reiniciar</button>\n    </div>\n  </div>\n\n  <div class=\"acciones\">\n    <button class=\"btn-comprobar\">&check; Comprobar respuestas</button>\n    <button class=\"btn-descargar-pdf\">&#8681; Descargar PDF</button>\n  </div>\n\n  <div class=\"feedback\"></div>\n</div>'),
