(5081,233,'_contenido_ficha_html','field_contenido_ficha_html'),
(5082,233,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n\r\n  <div class=\"instrucciones\">\r\n    <p><strong>Instrucciones:</strong> Observa, cuenta y elige la respuesta correcta. En algunas actividades escribe, arrastra o traza.</p>\r\n  </div>\r\n\r\n  <div class=\"contenedor-preguntas\">\r\n\r\n    <!-- 1 + 2) Simples (fila completa) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <p class=\"pregunta\">ÂżCuĂĄntas estrellas hay?</p>\r\n      <div class=\"visual\">â­ â­ â­</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <p class=\"pregunta\">Cuenta los globos:</p>\r\n      <div class=\"visual\">???? ???? ????</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 3) Fill blanks -->\r\n    <div class=\"ejercicio-fillblanks\">\r\n      <p class=\"pregunta-fillblanks\">Escribe el nĂșmero que falta:</p>\r\n      <p class=\"fillblanks-texto\">\r\n        ???? ???? ???? = <input class=\"fillblank-input\" data-respuesta=\"3\" placeholder=\"3\" />\r\n      </p>\r\n    </div>\r\n\r\n    <!-- 4) Drag & Drop -->\r\n    <div class=\"ejercicio-dragdrop\">\r\n      <p class=\"pregunta\">Arrastra el nĂșmero correcto al grupo de objetos:</p>\r\n      <div class=\"dragdrop-container\">\r\n        <div class=\"dragdrop-items\">\r\n          <div class=\"dragdrop-items-title\">NĂșmeros</div>\r\n          <div class=\"dragdrop-items-grid\">\r\n            <div class=\"dragdrop-item\" data-valor=\"2\">2</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"3\">3</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"4\">4</div>\r\n          </div>\r\n        </div>\r\n        <div class=\"dragdrop-zones\">\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"3\">\r\n            <div class=\"dragdrop-zone-title\">???? ???? ????</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 5 + 6) Simples (fila completa) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <p class=\"pregunta\">Selecciona el nĂșmero tres:</p>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"1\">1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <p class=\"pregunta\">ÂżCuĂĄntos corazones ves?</p>\r\n      <div class=\"visual\">â€ïž â€ïž â€ïž</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"6\">6</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 7) Memory (CORREGIDO) -->\r\n    <div class=\"ejercicio-memory\" data-pares=\"3\">\r\n      <p class=\"pregunta-memory\">Encuentra las parejas del nĂșmero 3:</p>\r\n\r\n      <div class=\"memory-stats\">\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Movimientos:</span> <span class=\"memory-moves\"><strong>0</strong></span></div>\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Parejas:</span> <span class=\"memory-pairs\"><strong>0/3</strong></span></div>\r\n      </div>\r\n\r\n      <div class=\"memory-grid\">\r\n        <div class=\"memory-card\" data-pair=\"3\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">3</div>\r\n        </div>\r\n        <div class=\"memory-card\" data-pair=\"3\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">3</div>\r\n        </div>\r\n\r\n        <div class=\"memory-card\" data-pair=\"â­\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">â­</div>\r\n        </div>\r\n        <div class=\"memory-card\" data-pair=\"â­\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">â­</div>\r\n        </div>\r\n\r\n        <div class=\"memory-card\" data-pair=\"????\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">????</div>\r\n        </div>\r\n        <div class=\"memory-card\" data-pair=\"????\">\r\n          <div class=\"memory-card-front\">?</div>\r\n          <div class=\"memory-card-back\">????</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"memory-actions\">\r\n        <button class=\"btn-reiniciar-memory\">Reiniciar</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 8) Wordsearch -->\r\n    <div class=\"ejercicio-wordsearch\">\r\n      <p class=\"pregunta-wordsearch\">Busca la palabra: TRES</p>\r\n      <div class=\"wordsearch-container\">\r\n        <div class=\"wordsearch-grid\">\r\n          <table class=\"wordsearch-table\" data-words=\'[\"TRES\"]\'>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">T</td><td class=\"wordsearch-cell\">R</td><td class=\"wordsearch-cell\">E</td><td class=\"wordsearch-cell\">S</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">O</td><td class=\"wordsearch-cell\">I</td><td class=\"wordsearch-cell\">U</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">B</td><td class=\"wordsearch-cell\">C</td><td class=\"wordsearch-cell\">D</td><td class=\"wordsearch-cell\">E</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">F</td><td class=\"wordsearch-cell\">G</td><td class=\"wordsearch-cell\">H</td><td class=\"wordsearch-cell\">I</td>\r\n            </tr>\r\n          </table>\r\n        </div>\r\n        <div class=\"wordsearch-words\">\r\n          <div class=\"wordsearch-words-title\">Palabras</div>\r\n          <div class=\"wordsearch-words-list\">\r\n            <span class=\"word-item\">TRES</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 9) Trazo -->\r\n    <div class=\"ejercicio-trazo\">\r\n      <p class=\"pregunta-trazo\">Traza el nĂșmero 3:</p>\r\n      <div class=\"trazo-canvas-container\">\r\n        <span class=\"trazo-guia\">3</span>\r\n        <canvas width=\"320\" height=\"200\"></canvas>\r\n      </div>\r\n      <div class=\"trazo-actions\">\r\n        <button class=\"btn-borrar-trazo\">Borrar</button>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <div class=\"acciones\">\r\n    <button class=\"btn-comprobar\">Comprobar</button>\r\n  </div>\r\n\r\n  <div class=\"feedback\" style=\"display:none;\"></div>\r\n</div>'),
