(6153,284,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n\r\n  <div class=\"instrucciones\">\r\n    ???? ÂĄBienvenid@ al taller de la Calabaza! Cuenta, arrastra, escribe, busca y traza.\r\n    Completa todas las actividades para ayudar a la calabaza a brillar.\r\n  </div>\r\n\r\n  <div class=\"contenedor-preguntas\">\r\n\r\n    <!-- 1) SIMPLE -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <div class=\"pregunta\">1. ÂżCuĂĄntas calabazas ves?</div>\r\n      <div class=\"visual\">???? ???? ????</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 2) SIMPLE -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4\">\r\n      <div class=\"pregunta\">2. ÂżCuĂĄntas velas hay?</div>\r\n      <div class=\"visual\">????ïž ????ïž ????ïž ????ïž</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 3) FILL BLANKS -->\r\n    <div class=\"ejercicio-fillblanks\">\r\n      <div class=\"pregunta-fillblanks\">3. Completa el nĂșmero</div>\r\n      <div class=\"fillblanks-texto\">\r\n        ???? ???? ???? ???? â Hay <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"4\" maxlength=\"1\"> fantasmas.\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 4) FILL BLANKS -->\r\n    <div class=\"ejercicio-fillblanks\">\r\n      <div class=\"pregunta-fillblanks\">4. Escribe el nĂșmero correcto</div>\r\n      <div class=\"fillblanks-texto\">\r\n        ????ïž ????ïž â Hay <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"2\" maxlength=\"1\"> araĂ±as.\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 5) DRAG & DROP -->\r\n    <div class=\"ejercicio-dragdrop\">\r\n      <div class=\"pregunta\">5. Arrastra cada grupo al nĂșmero correcto</div>\r\n      <div class=\"dragdrop-container\">\r\n        <div class=\"dragdrop-items\">\r\n          <div class=\"dragdrop-items-title\">Grupos</div>\r\n          <div class=\"dragdrop-items-grid\">\r\n            <div class=\"dragdrop-item\" data-valor=\"1\">????</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"2\">????????</div>\r\n            <div class=\"dragdrop-item\" data-valor=\"3\">????????????</div>\r\n          </div>\r\n        </div>\r\n        <div class=\"dragdrop-zones\">\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"1\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 1</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"2\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 2</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"3\">\r\n            <div class=\"dragdrop-zone-title\">NĂșmero 3</div>\r\n            <div class=\"dragdrop-zone-content\"></div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 6) WORDSEARCH -->\r\n    <div class=\"ejercicio-wordsearch\">\r\n      <div class=\"pregunta-wordsearch\">6. Busca la palabra: CALABAZA</div>\r\n      <div class=\"wordsearch-container\">\r\n        <div class=\"wordsearch-grid\">\r\n          <table class=\"wordsearch-table\" data-words=\'[\"CALABAZA\"]\'>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">C</td><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">L</td><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">B</td><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">Z</td><td class=\"wordsearch-cell\">A</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">B</td><td class=\"wordsearch-cell\">F</td><td class=\"wordsearch-cell\">G</td><td class=\"wordsearch-cell\">H</td><td class=\"wordsearch-cell\">I</td><td class=\"wordsearch-cell\">J</td><td class=\"wordsearch-cell\">K</td><td class=\"wordsearch-cell\">L</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">M</td><td class=\"wordsearch-cell\">N</td><td class=\"wordsearch-cell\">O</td><td class=\"wordsearch-cell\">P</td><td class=\"wordsearch-cell\">Q</td><td class=\"wordsearch-cell\">R</td><td class=\"wordsearch-cell\">S</td><td class=\"wordsearch-cell\">T</td>\r\n            </tr>\r\n            <tr>\r\n              <td class=\"wordsearch-cell\">U</td><td class=\"wordsearch-cell\">V</td><td class=\"wordsearch-cell\">W</td><td class=\"wordsearch-cell\">X</td><td class=\"wordsearch-cell\">Y</td><td class=\"wordsearch-cell\">Z</td><td class=\"wordsearch-cell\">A</td><td class=\"wordsearch-cell\">B</td>\r\n            </tr>\r\n          </table>\r\n        </div>\r\n        <div class=\"wordsearch-words\">\r\n          <div class=\"wordsearch-words-title\">Palabras</div>\r\n          <div class=\"wordsearch-words-list\">\r\n            <span class=\"word-item\">CALABAZA</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 7) TRAZO (CALABAZA) -->\r\n    <div class=\"ejercicio-trazo\">\r\n      <div class=\"pregunta-trazo\">7. Traza la calabaza</div>\r\n      <div class=\"trazo-canvas-container\">\r\n        <span class=\"trazo-guia\">????</span>\r\n        <canvas width=\"320\" height=\"200\"></canvas>\r\n      </div>\r\n      <div class=\"trazo-actions\">\r\n        <button class=\"btn-borrar-trazo\">Borrar</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 8) MEMORY -->\r\n    <div class=\"ejercicio-memory\" data-pares=\"3\">\r\n      <div class=\"pregunta-memory\">8. Encuentra las parejas</div>\r\n\r\n      <div class=\"memory-stats\">\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Movimientos:</span> <span class=\"memory-moves\"><strong>0</strong></span></div>\r\n        <div class=\"stat-item\"><span class=\"stat-label\">Parejas:</span> <span class=\"memory-pairs\"><strong>0/3</strong></span></div>\r\n      </div>\r\n\r\n      <div class=\"memory-grid\">\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????ïž\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????ïž</div></div>\r\n        <div class=\"memory-card\" data-pair=\"????ïž\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">????ïž</div></div>\r\n      </div>\r\n\r\n      <div class=\"memory-actions\">\r\n        <button class=\"btn-reiniciar-memory\">Reiniciar</button>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <div class=\"acciones\">\r\n    <button class=\"btn-comprobar\">â ÂĄYa terminĂ©! Comprobar respuestas</button>\r\n    <button class=\"btn-descargar-pdf\">???? Descargar PDF</button>\r\n  </div>\r\n\r\n  <div class=\"feedback\" style=\"display:none;\"></div>\r\n\r\n</div>'),
