(10630,439,'contenido_ficha_html','<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">Ordena los n&uacute;meros del menor al mayor. Empieza por las decenas y, si son iguales, mira las unidades.</div>\n\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"10, 40, 70\">\n      <div class=\"pregunta\">1. Ordena de menor a mayor</div>\n      <div class=\"visual\">70 - 10 - 40</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"10, 40, 70\">10, 40, 70</button>\n        <button class=\"opcion-btn\" data-valor=\"70, 40, 10\">70, 40, 10</button>\n        <button class=\"opcion-btn\" data-valor=\"10, 70, 40\">10, 70, 40</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"23, 45, 67, 89\">\n      <div class=\"pregunta\">2. Elige la serie correcta</div>\n      <div class=\"visual\">67 - 23 - 89 - 45</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"23, 45, 67, 89\">23, 45, 67, 89</button>\n        <button class=\"opcion-btn\" data-valor=\"23, 67, 45, 89\">23, 67, 45, 89</button>\n        <button class=\"opcion-btn\" data-valor=\"89, 67, 45, 23\">89, 67, 45, 23</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"12, 31, 56, 78\">\n      <div class=\"pregunta\">3. Ordena estos n&uacute;meros</div>\n      <div class=\"visual\">56 - 12 - 78 - 31</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"12, 31, 56, 78\">12, 31, 56, 78</button>\n        <button class=\"opcion-btn\" data-valor=\"12, 56, 31, 78\">12, 56, 31, 78</button>\n        <button class=\"opcion-btn\" data-valor=\"31, 12, 56, 78\">31, 12, 56, 78</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"21, 44, 58, 90\">\n      <div class=\"pregunta\">4. Marca la opci&oacute;n correcta</div>\n      <div class=\"visual\">90 - 44 - 21 - 58</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"21, 44, 58, 90\">21, 44, 58, 90</button>\n        <button class=\"opcion-btn\" data-valor=\"21, 58, 44, 90\">21, 58, 44, 90</button>\n        <button class=\"opcion-btn\" data-valor=\"44, 21, 58, 90\">44, 21, 58, 90</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"34, 37, 39\">\n      <div class=\"pregunta\">5. N&uacute;meros muy cercanos</div>\n      <div class=\"visual\">39 - 34 - 37</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"34, 37, 39\">34, 37, 39</button>\n        <button class=\"opcion-btn\" data-valor=\"37, 34, 39\">37, 34, 39</button>\n        <button class=\"opcion-btn\" data-valor=\"34, 39, 37\">34, 39, 37</button>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"62, 65, 68\">\n      <div class=\"pregunta\">6. Ordena de menor a mayor</div>\n      <div class=\"visual\">68 - 62 - 65</div>\n      <div class=\"opciones\">\n        <button class=\"opcion-btn\" data-valor=\"62, 65, 68\">62, 65, 68</button>\n        <button class=\"opcion-btn\" data-valor=\"62, 68, 65\">62, 68, 65</button>\n        <button class=\"opcion-btn\" data-valor=\"65, 62, 68\">65, 62, 68</button>\n      </div>\n    </div>\n\n    <div class=\"ejercicio-serie ejercicio-fillblanks\">\n      <div class=\"pregunta-fillblanks\">7. Completa las series</div>\n      <div class=\"serie-rows\">\n        <div class=\"serie-row\">\n          <span>12</span><span class=\"serie-sep\">-</span>\n          <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"18\" maxlength=\"2\">\n          <span class=\"serie-sep\">-</span><span>24</span><span class=\"serie-sep\">-</span><span>30</span>\n        </div>\n        <div class=\"serie-row\">\n          <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"41\" maxlength=\"2\">\n          <span class=\"serie-sep\">-</span><span>42</span><span class=\"serie-sep\">-</span><span>43</span><span class=\"serie-sep\">-</span>\n          <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"44\" maxlength=\"2\">\n        </div>\n      </div>\n    </div>\n\n    <div class=\"ejercicio-dragdrop\">\n      <div class=\"pregunta\">8. Arrastra cada n&uacute;mero a su posici&oacute;n (del menor al mayor)</div>\n      <div class=\"dragdrop-container\">\n        <div class=\"dragdrop-items\">\n          <div class=\"dragdrop-items-title\">N&uacute;meros</div>\n          <div class=\"dragdrop-items-grid\">\n            <div class=\"dragdrop-item\" data-valor=\"26\">26</div>\n            <div class=\"dragdrop-item\" data-valor=\"14\">14</div>\n            <div class=\"dragdrop-item\" data-valor=\"38\">38</div>\n            <div class=\"dragdrop-item\" data-valor=\"19\">19</div>\n          </div>\n        </div>\n        <div class=\"dragdrop-zones\">\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"14\">\n            <div class=\"dragdrop-zone-title\">1&ordm;</div>\n            <div class=\"dragdrop-zone-content\"></div>\n          </div>\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"19\">\n            <div class=\"dragdrop-zone-title\">2&ordm;</div>\n            <div class=\"dragdrop-zone-content\"></div>\n          </div>\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"26\">\n            <div class=\"dragdrop-zone-title\">3&ordm;</div>\n            <div class=\"dragdrop-zone-content\"></div>\n          </div>\n          <div class=\"dragdrop-zone\" data-respuesta-correcta=\"38\">\n            <div class=\"dragdrop-zone-title\">4&ordm;</div>\n            <div class=\"dragdrop-zone-content\"></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"dragdrop-actions\">\n        <button class=\"btn-reiniciar-dragdrop\">Reiniciar</button>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"acciones\">\n    <button class=\"btn-comprobar\">Comprobar respuestas</button>\n    <button class=\"btn-descargar-pdf\">Descargar PDF</button>\n  </div>\n\n  <div class=\"feedback\"></div>\n</div>'),
