(10632,440,'contenido_ficha_html','<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">Compara numeros de dos cifras. Primero mira decenas; si son iguales, compara unidades.</div>\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"menor\">\n      <div class=\"pregunta\">1) 34 __ 39</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"menor\">&lt;</button><button class=\"opcion-btn\" data-valor=\"mayor\">&gt;</button><button class=\"opcion-btn\" data-valor=\"igual\">=</button></div>\n    </div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"mayor\">\n      <div class=\"pregunta\">2) 78 __ 73</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"menor\">&lt;</button><button class=\"opcion-btn\" data-valor=\"mayor\">&gt;</button><button class=\"opcion-btn\" data-valor=\"igual\">=</button></div>\n    </div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"igual\">\n      <div class=\"pregunta\">3) 66 __ 66</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"menor\">&lt;</button><button class=\"opcion-btn\" data-valor=\"mayor\">&gt;</button><button class=\"opcion-btn\" data-valor=\"igual\">=</button></div>\n    </div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"menor\">\n      <div class=\"pregunta\">4) 45 __ 54</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"menor\">&lt;</button><button class=\"opcion-btn\" data-valor=\"mayor\">&gt;</button><button class=\"opcion-btn\" data-valor=\"igual\">=</button></div>\n    </div>\n\n    <div class=\"ejercicio-serie ejercicio-fillblanks\">\n      <div class=\"pregunta-fillblanks\">5) Escribe el simbolo correcto</div>\n      <div class=\"serie-rows\">\n        <div class=\"serie-row\">47 <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"<\" maxlength=\"1\"> 52</div>\n        <div class=\"serie-row\">90 <input type=\"text\" class=\"fillblank-input\" data-respuesta=\">\" maxlength=\"1\"> 79</div>\n      </div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\n      <div class=\"pregunta\">6) 62 es mayor que 26</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div>\n    </div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"falso\">\n      <div class=\"pregunta\">7) 81 es menor que 18</div>\n      <div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div>\n    </div>\n\n    <div class=\"ejercicio-dragdrop\">\n      <div class=\"pregunta\">8) Arrastra cada comparacion a su grupo</div>\n      <div class=\"dragdrop-container\">\n        <div class=\"dragdrop-items\"><div class=\"dragdrop-items-title\">Comparaciones</div><div class=\"dragdrop-items-grid\"><div class=\"dragdrop-item\" data-valor=\"mayor\">84 y 48</div><div class=\"dragdrop-item\" data-valor=\"igual\">33 y 33</div><div class=\"dragdrop-item\" data-valor=\"menor\">29 y 92</div></div></div>\n        <div class=\"dragdrop-zones\"><div class=\"dragdrop-zone\" data-respuesta-correcta=\"menor\"><div class=\"dragdrop-zone-title\">Primer numero menor</div><div class=\"dragdrop-zone-content\"></div></div><div class=\"dragdrop-zone\" data-respuesta-correcta=\"igual\"><div class=\"dragdrop-zone-title\">Numeros iguales</div><div class=\"dragdrop-zone-content\"></div></div><div class=\"dragdrop-zone\" data-respuesta-correcta=\"mayor\"><div class=\"dragdrop-zone-title\">Primer numero mayor</div><div class=\"dragdrop-zone-content\"></div></div></div>\n      </div>\n      <div class=\"dragdrop-actions\"><button class=\"btn-reiniciar-dragdrop\">Reiniciar</button></div>\n    </div>\n  </div>\n  <div class=\"acciones\"><button class=\"btn-comprobar\">Comprobar respuestas</button><button class=\"btn-descargar-pdf\">Descargar PDF</button></div><div class=\"feedback\"></div>\n</div>'),
