(10636,441,'contenido_ficha_html','<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">Lee, identifica los datos y suma para encontrar el total.</div>\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"8\"><div class=\"pregunta\">1) Ana tiene 5 globos y le regalan 3. Total:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"7\">7</button><button class=\"opcion-btn\" data-valor=\"8\">8</button><button class=\"opcion-btn\" data-valor=\"9\">9</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"10\"><div class=\"pregunta\">2) Hay 6 ninos y 4 ninas. Total:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"9\">9</button><button class=\"opcion-btn\" data-valor=\"10\">10</button><button class=\"opcion-btn\" data-valor=\"11\">11</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"7\"><div class=\"pregunta\">3) Habia 2 pajaros y llegan 5. Total:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"6\">6</button><button class=\"opcion-btn\" data-valor=\"7\">7</button><button class=\"opcion-btn\" data-valor=\"8\">8</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"9\"><div class=\"pregunta\">4) Marta tiene 4 cromos y compra 5. Total:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"8\">8</button><button class=\"opcion-btn\" data-valor=\"9\">9</button><button class=\"opcion-btn\" data-valor=\"10\">10</button></div></div>\n\n    <div class=\"ejercicio-serie ejercicio-fillblanks\">\n      <div class=\"pregunta-fillblanks\">5) Calcula las sumas</div>\n      <div class=\"serie-rows\"><div class=\"serie-row\">2 + 5 = <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"7\" maxlength=\"2\"></div><div class=\"serie-row\">4 + 4 = <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"8\" maxlength=\"2\"></div></div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\"><div class=\"pregunta\">6) 3 + 4 = 7</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"falso\"><div class=\"pregunta\">7) 6 + 2 = 10</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n\n    <div class=\"ejercicio-dragdrop\">\n      <div class=\"pregunta\">8) Arrastra cada suma a su resultado</div>\n      <div class=\"dragdrop-container\">\n        <div class=\"dragdrop-items\"><div class=\"dragdrop-items-title\">Operaciones</div><div class=\"dragdrop-items-grid\"><div class=\"dragdrop-item\" data-valor=\"7\">3 + 4</div><div class=\"dragdrop-item\" data-valor=\"9\">5 + 4</div><div class=\"dragdrop-item\" data-valor=\"10\">6 + 4</div></div></div>\n        <div class=\"dragdrop-zones\"><div class=\"dragdrop-zone\" data-respuesta-correcta=\"7\"><div class=\"dragdrop-zone-title\">Resultado 7</div><div class=\"dragdrop-zone-content\"></div></div><div class=\"dragdrop-zone\" data-respuesta-correcta=\"9\"><div class=\"dragdrop-zone-title\">Resultado 9</div><div class=\"dragdrop-zone-content\"></div></div><div class=\"dragdrop-zone\" data-respuesta-correcta=\"10\"><div class=\"dragdrop-zone-title\">Resultado 10</div><div class=\"dragdrop-zone-content\"></div></div></div>\n      </div>\n      <div class=\"dragdrop-actions\"><button class=\"btn-reiniciar-dragdrop\">Reiniciar</button></div>\n    </div>\n  </div>\n  <div class=\"acciones\"><button class=\"btn-comprobar\">Comprobar respuestas</button><button class=\"btn-descargar-pdf\">Descargar PDF</button></div><div class=\"feedback\"></div>\n</div>'),
