(10640,442,'contenido_ficha_html','<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">Lee cada situacion y resta para saber cuantos quedan.</div>\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"6\"><div class=\"pregunta\">1) Tenia 9 canicas y perdi 3. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"5\">5</button><button class=\"opcion-btn\" data-valor=\"6\">6</button><button class=\"opcion-btn\" data-valor=\"7\">7</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4\"><div class=\"pregunta\">2) Habia 7 galletas y comen 3. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"3\">3</button><button class=\"opcion-btn\" data-valor=\"4\">4</button><button class=\"opcion-btn\" data-valor=\"5\">5</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"2\"><div class=\"pregunta\">3) En la caja hay 6 lapices y saco 4. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"1\">1</button><button class=\"opcion-btn\" data-valor=\"2\">2</button><button class=\"opcion-btn\" data-valor=\"3\">3</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"5\"><div class=\"pregunta\">4) Habia 10 flores y se marchitan 5. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"4\">4</button><button class=\"opcion-btn\" data-valor=\"5\">5</button><button class=\"opcion-btn\" data-valor=\"6\">6</button></div></div>\n\n    <div class=\"ejercicio-memory\" data-pares=\"3\">\n      <div class=\"pregunta-memory\">5) Juego rapido: encuentra cada resta con su resultado</div>\n      <div class=\"memory-grid\">\n        <div class=\"memory-card\" data-pair=\"par1\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">8-3</div></div>\n        <div class=\"memory-card\" data-pair=\"par1\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">5</div></div>\n        <div class=\"memory-card\" data-pair=\"par2\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">9-4</div></div>\n        <div class=\"memory-card\" data-pair=\"par2\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">5</div></div>\n        <div class=\"memory-card\" data-pair=\"par3\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">7-6</div></div>\n        <div class=\"memory-card\" data-pair=\"par3\"><div class=\"memory-card-front\">?</div><div class=\"memory-card-back\">1</div></div>\n      </div>\n      <div class=\"memory-stats\"><span class=\"memory-moves\">Movimientos: <strong>0</strong></span><span class=\"memory-pairs\">Parejas: <strong>0/3</strong></span></div>\n      <div class=\"memory-actions\"><button class=\"btn-reiniciar-memory\">Reiniciar</button></div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\"><div class=\"pregunta\">6) 8 - 2 = 6</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"falso\"><div class=\"pregunta\">7) 9 - 3 = 7</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n\n    <div class=\"ejercicio-serie ejercicio-fillblanks\"><div class=\"pregunta-fillblanks\">8) Completa: 10 - 4 = <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"6\" maxlength=\"2\"></div></div>\n  </div>\n  <div class=\"acciones\"><button class=\"btn-comprobar\">Comprobar respuestas</button><button class=\"btn-descargar-pdf\">Descargar PDF</button></div><div class=\"feedback\"></div>\n</div>'),
