(10644,443,'contenido_ficha_html','<div class=\"ficha-educativa\">\n  <div class=\"instrucciones\">Decide si debes sumar o restar, y luego calcula el resultado.</div>\n  <div class=\"contenedor-preguntas\">\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"8\"><div class=\"pregunta\">1) Tengo 5 pegatinas y me dan 3 mas. Resultado:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"7\">7</button><button class=\"opcion-btn\" data-valor=\"8\">8</button><button class=\"opcion-btn\" data-valor=\"9\">9</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4\"><div class=\"pregunta\">2) Habia 9 galletas y comieron 5. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"3\">3</button><button class=\"opcion-btn\" data-valor=\"4\">4</button><button class=\"opcion-btn\" data-valor=\"5\">5</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"10\"><div class=\"pregunta\">3) En el parque hay 6 ninos y llegan 4 mas. Total:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"9\">9</button><button class=\"opcion-btn\" data-valor=\"10\">10</button><button class=\"opcion-btn\" data-valor=\"11\">11</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"2\"><div class=\"pregunta\">4) Tenia 7 monedas y gasto 5. Quedan:</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"1\">1</button><button class=\"opcion-btn\" data-valor=\"2\">2</button><button class=\"opcion-btn\" data-valor=\"3\">3</button></div></div>\n\n    <div class=\"ejercicio-dragdrop\">\n      <div class=\"pregunta\">5) Arrastra cada situacion a suma o resta</div>\n      <div class=\"dragdrop-container\">\n        <div class=\"dragdrop-items\"><div class=\"dragdrop-items-title\">Situaciones</div><div class=\"dragdrop-items-grid\"><div class=\"dragdrop-item\" data-valor=\"suma\">Tengo 3 y me dan 4</div><div class=\"dragdrop-item\" data-valor=\"resta\">Tenia 8 y perdi 2</div><div class=\"dragdrop-item\" data-valor=\"suma\">Hay 5 y llegan 2</div></div></div>\n        <div class=\"dragdrop-zones\"><div class=\"dragdrop-zone\" data-respuesta-correcta=\"suma\"><div class=\"dragdrop-zone-title\">Suma</div><div class=\"dragdrop-zone-content\"></div></div><div class=\"dragdrop-zone\" data-respuesta-correcta=\"resta\"><div class=\"dragdrop-zone-title\">Resta</div><div class=\"dragdrop-zone-content\"></div></div></div>\n      </div>\n      <div class=\"dragdrop-actions\"><button class=\"btn-reiniciar-dragdrop\">Reiniciar</button></div>\n    </div>\n\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\"><div class=\"pregunta\">6) \"Llegan mas\" suele ser suma</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\"><div class=\"pregunta\">7) \"Se van\" suele ser resta</div><div class=\"opciones\"><button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button><button class=\"opcion-btn\" data-valor=\"falso\">Falso</button></div></div>\n\n    <div class=\"ejercicio-serie ejercicio-fillblanks\"><div class=\"pregunta-fillblanks\">8) Completa: 4 + 3 = <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"7\" maxlength=\"2\"> y 9 - 4 = <input type=\"text\" class=\"fillblank-input\" data-respuesta=\"5\" maxlength=\"2\"></div></div>\n  </div>\n  <div class=\"acciones\"><button class=\"btn-comprobar\">Comprobar respuestas</button><button class=\"btn-descargar-pdf\">Descargar PDF</button></div><div class=\"feedback\"></div>\n</div>'),
