(359,1,'2026-01-29 16:38:42','2026-01-29 16:38:42','function fichas_encolar_trazo_assets() {\r\n    if ( is_singular(\'ficha\') ) {\r\n        // CSS de trazo\r\n        wp_enqueue_style(\r\n            \'fichas-trazo-css\',\r\n            get_stylesheet_directory_uri() . \'/css/trazo-addon.css\',\r\n            array(),\r\n            \'1.0.0\'\r\n        );\r\n\r\n        // JS de trazo\r\n        wp_enqueue_script(\r\n            \'fichas-trazo-js\',\r\n            get_stylesheet_directory_uri() . \'/js/trazo-addon.js\',\r\n            array(),\r\n            \'1.0.0\',\r\n            true\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_encolar_trazo_assets\');\r\n\r\n','Encolar CSS y JS adicionales para ejercicios de trazo','','draft','closed','closed','','encolar-css-y-js-adicionales-para-ejercicios-de-trazo','','','2026-01-30 12:29:59','2026-01-30 12:29:59','',0,'http://localhost:8080/?post_type=wpcode&#038;p=359',0,'wpcode','',0),
(360,1,'2026-01-29 18:15:47','2026-01-29 18:15:47','/**\r\n * Encolar CSS y JS para ejercicios Drag & Drop\r\n * Solo en single-ficha.php\r\n * \r\n * AĂ±adir a WPCode como nuevo snippet\r\n */\r\nfunction fichas_encolar_dragdrop_assets() {\r\n    // Solo en el CPT \'ficha\'\r\n    if ( is_singular(\'ficha\') ) {\r\n\r\n        // CSS de drag & drop\r\n        wp_enqueue_style(\r\n            \'fichas-dragdrop-css\',\r\n            get_stylesheet_directory_uri() . \'/css/dragdrop-addon.css\',\r\n            array(), // Sin dependencias\r\n            \'1.0.0\'\r\n        );\r\n\r\n        // JS de drag & drop\r\n        wp_enqueue_script(\r\n            \'fichas-dragdrop-js\',\r\n            get_stylesheet_directory_uri() . \'/js/dragdrop-addon.js\',\r\n            array(), // Sin dependencias\r\n            \'1.0.0\',\r\n            true // Cargar en el footer\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_encolar_dragdrop_assets\');','Encolar CSS y JS para ejercicios Drag & Drop','','draft','closed','closed','','encolar-css-y-js-para-ejercicios-drag-drop','','','2026-01-30 12:29:57','2026-01-30 12:29:57','',0,'http://localhost:8080/wpcode/encolar-css-y-js-para-ejercicios-drag-drop/',0,'wpcode','',0),
(361,1,'2026-01-30 08:26:59','2026-01-30 08:26:59','\r\n/**\r\n * Encolar CSS y JS para ejercicios Memory Game\r\n * Solo en single-ficha.php\r\n * \r\n * AĂ±adir a WPCode como nuevo snippet\r\n */\r\nfunction fichas_encolar_memory_assets() {\r\n    // Solo en el CPT \'ficha\'\r\n    if ( is_singular(\'ficha\') ) {\r\n\r\n        // CSS de memory game\r\n        wp_enqueue_style(\r\n            \'fichas-memory-css\',\r\n            get_stylesheet_directory_uri() . \'/css/memory-addon.css\',\r\n            array(), // Sin dependencias\r\n            \'1.0.0\'\r\n        );\r\n\r\n        // JS de memory game\r\n        wp_enqueue_script(\r\n            \'fichas-memory-js\',\r\n            get_stylesheet_directory_uri() . \'/js/memory-addon.js\',\r\n            array(), // Sin dependencias\r\n            \'1.0.0\',\r\n            true // Cargar en el footer\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_encolar_memory_assets\');','Encolar CSS y JS para ejercicios Memory Game','','draft','closed','closed','','encolar-css-y-js-para-ejercicios-memory-game','','','2026-01-30 12:29:55','2026-01-30 12:29:55','',0,'http://localhost:8080/wpcode/encolar-css-y-js-para-ejercicios-memory-game/',0,'wpcode','',0),
(362,1,'2026-01-30 09:28:32','2026-01-30 09:28:32','/**\r\n * Contador de visualizaciones de fichas\r\n * Incrementa automĂĄticamente cada vez que se visita una ficha\r\n */\r\n\r\n// Incrementar contador al visitar una ficha\r\nfunction fichas_incrementar_vistas() {\r\n    if (is_singular(\'ficha\')) {\r\n        global $post;\r\n        \r\n        // Obtener vistas actuales\r\n        $vistas = get_post_meta($post->ID, \'fichas_vistas\', true);\r\n        $vistas = empty($vistas) ? 0 : intval($vistas);\r\n        \r\n        // Incrementar\r\n        $vistas++;\r\n        \r\n        // Guardar\r\n        update_post_meta($post->ID, \'fichas_vistas\', $vistas);\r\n    }\r\n}\r\nadd_action(\'wp_head\', \'fichas_incrementar_vistas\');\r\n\r\n// FunciĂłn helper para obtener vistas en templates\r\nfunction fichas_get_vistas($post_id = null) {\r\n    if (!$post_id) {\r\n        global $post;\r\n        $post_id = $post->ID;\r\n    }\r\n    \r\n    $vistas = get_post_meta($post_id, \'fichas_vistas\', true);\r\n    return empty($vistas) ? 0 : intval($vistas);\r\n}\r\n\r\n// Formatear nĂșmero con separador de miles\r\nfunction fichas_format_vistas($post_id = null) {\r\n    $vistas = fichas_get_vistas($post_id);\r\n    return number_format($vistas, 0, \',\', \'.\');\r\n}\r\n','Contador de visualizaciones de fichas','','publish','closed','closed','','contador-de-visualizaciones-de-fichas','','','2026-01-30 09:28:33','2026-01-30 09:28:33','',0,'http://localhost:8080/wpcode/contador-de-visualizaciones-de-fichas/',0,'wpcode','',0),
(363,1,'2026-01-30 11:33:52','2026-01-30 11:33:52','function encolar_fillblanks_addon() {\r\n    if (is_singular(\'ficha\')) {\r\n        wp_enqueue_style(\r\n            \'fillblanks-addon\',\r\n            get_stylesheet_directory_uri() . \'/css/fillblanks-addon.css\',\r\n            array(),\r\n            \'1.0\'\r\n        );\r\n        \r\n        wp_enqueue_script(\r\n            \'fillblanks-addon\',\r\n            get_stylesheet_directory_uri() . \'/js/fillblanks-addon.js\',\r\n            array(),\r\n            \'1.0\',\r\n            true\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'encolar_fillblanks_addon\');','Encolar fillblanks-addon','','draft','closed','closed','','encolar-fillblanks-addon','','','2026-01-30 12:29:50','2026-01-30 12:29:50','',0,'http://localhost:8080/?post_type=wpcode&#038;p=363',0,'wpcode','',0),
(364,1,'2026-01-30 11:37:31','2026-01-30 11:37:31','function encolar_truefalse_addon() {\r\n    if (is_singular(\'ficha\')) {\r\n        wp_enqueue_style(\r\n            \'truefalse-addon\',\r\n            get_stylesheet_directory_uri() . \'/css/truefalse-addon.css\',\r\n            array(),\r\n            \'1.0\'\r\n        );\r\n        \r\n        wp_enqueue_script(\r\n            \'truefalse-addon\',\r\n            get_stylesheet_directory_uri() . \'/js/truefalse-addon.js\',\r\n            array(),\r\n            \'1.0\',\r\n            true\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'encolar_truefalse_addon\');\r\n','Encolar True o False','','draft','closed','closed','','encolar-true-o-false','','','2026-01-30 12:29:48','2026-01-30 12:29:48','',0,'http://localhost:8080/?post_type=wpcode&#038;p=364',0,'wpcode','',0),
(365,1,'2026-01-30 11:41:04','2026-01-30 11:41:04','function encolar_wordsearch_addon() {\r\n    if (is_singular(\'ficha\')) {\r\n        wp_enqueue_style(\r\n            \'wordsearch-addon\',\r\n            get_stylesheet_directory_uri() . \'/css/wordsearch-addon.css\',\r\n            array(),\r\n            \'1.0\'\r\n        );\r\n        \r\n        wp_enqueue_script(\r\n            \'wordsearch-addon\',\r\n            get_stylesheet_directory_uri() . \'/js/wordsearch-addon.js\',\r\n            array(),\r\n            \'1.0\',\r\n            true\r\n        );\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'encolar_wordsearch_addon\');\r\n','Encolar Wordsearch','','draft','closed','closed','','encolar-wordsearch','','','2026-01-30 12:29:51','2026-01-30 12:29:51','',0,'http://localhost:8080/?post_type=wpcode&#038;p=365',0,'wpcode','',0),
(366,1,'2026-01-30 12:30:48','2026-01-30 12:30:48','/**\r\n * ENQUEUE UNIFICADO E INTELIGENTE - Fichas.es\r\n * Carga CSS/JS solo si la ficha los necesita (detecciĂłn automĂĄtica)\r\n * VersiĂłn 2.2 - Con soporte PDF\r\n */\r\n\r\nfunction fichas_enqueue_inteligente() {\r\n    // Solo en single ficha\r\n    if (!is_singular(\'ficha\')) return;\r\n\r\n    // Obtener contenido de la ficha actual\r\n    global $post;\r\n    $contenido = get_field(\'contenido_ficha_html\', $post->ID);\r\n    if (empty($contenido)) {\r\n        $contenido = $post->post_content;\r\n    }\r\n\r\n    // ============================================\r\n    // 1. LIBRERĂAS PDF (si usas descarga PDF)\r\n    // ============================================\r\n    \r\n    // html2canvas\r\n    wp_enqueue_script(\'html2canvas\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js\',\r\n        array(), \'1.4.1\', true);\r\n    \r\n    // jsPDF\r\n    wp_enqueue_script(\'jspdf\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js\',\r\n        array(), \'2.5.1\', true);\r\n    \r\n    // html2pdf (depende de html2canvas y jspdf)\r\n    wp_enqueue_script(\'html2pdf\',\r\n        \'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js\',\r\n        array(\'html2canvas\', \'jspdf\'), \'0.10.1\', true);\r\n\r\n    // ============================================\r\n    // 2. ARCHIVOS BASE (siempre se cargan)\r\n    // ============================================\r\n    \r\n    wp_enqueue_style(\'fichas-base\',\r\n        get_stylesheet_directory_uri() . \'/css/fichas.css\',\r\n        array(), \'2.5\');\r\n    \r\n wp_enqueue_script(\'fichas-base\',\r\n    get_stylesheet_directory_uri() . \'/js/fichas.js\',\r\n    array(), \'2.9\', true); // â VersiĂłn 2.9\r\n\r\n    // ============================================\r\n    // 3. ADDONS (carga condicional inteligente)\r\n    // ============================================\r\n    \r\n    $addons = array(\r\n        \'truefalse\' => array(\r\n            \'detectores\' => array(\'bloque-truefalse\', \'ejercicio-truefalse\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'fillblanks\' => array(\r\n            \'detectores\' => array(\'bloque-fillblanks\', \'ejercicio-fillblanks\', \'fillblank-input\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'wordsearch\' => array(\r\n            \'detectores\' => array(\'bloque-wordsearch\', \'ejercicio-wordsearch\', \'wordsearch-table\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'dragdrop\' => array(\r\n            \'detectores\' => array(\'ejercicio-dragdrop\', \'dragdrop-item\', \'dragdrop-zone\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'memory\' => array(\r\n            \'detectores\' => array(\'ejercicio-memory\', \'memory-card\', \'memory-grid\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        ),\r\n        \'trazo\' => array(\r\n            \'detectores\' => array(\'ejercicio-trazo\', \'canvas-trazo\', \'canvas-container\'),\r\n            \'css\' => true,\r\n            \'js\' => true\r\n        )\r\n    );\r\n\r\n    // Detectar y cargar addons necesarios\r\n    foreach ($addons as $addon => $config) {\r\n        $necesita_addon = false;\r\n\r\n        foreach ($config[\'detectores\'] as $detector) {\r\n            if (stripos($contenido, $detector) !== false) {\r\n                $necesita_addon = true;\r\n                break;\r\n            }\r\n        }\r\n\r\n        if ($necesita_addon && $config[\'css\']) {\r\n            wp_enqueue_style(\r\n                $addon . \'-addon\',\r\n                get_stylesheet_directory_uri() . \'/css/\' . $addon . \'-addon.css\',\r\n                array(\'fichas-base\'),\r\n                \'2.2\'\r\n            );\r\n        }\r\n\r\n        if ($necesita_addon && $config[\'js\']) {\r\n            wp_enqueue_script(\r\n                $addon . \'-addon\',\r\n                get_stylesheet_directory_uri() . \'/js/\' . $addon . \'-addon.js\',\r\n                array(\'fichas-base\'),\r\n                \'2.2\',\r\n                true\r\n            );\r\n        }\r\n    }\r\n}\r\nadd_action(\'wp_enqueue_scripts\', \'fichas_enqueue_inteligente\');\r\n\r\n','ENQUEUE UNIFICADO E INTELIGENTE - Fichas.es','','publish','closed','closed','','enqueue-unificado-e-inteligente-fichas-es','','','2026-02-02 12:22:05','2026-02-02 12:22:05','',0,'http://localhost:8080/?post_type=wpcode&#038;p=366',0,'wpcode','',0),
(367,1,'2026-02-03 13:59:09','2026-02-03 13:59:09','/**\r\n * ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n * FICHAS.ES - URLS JERĂRQUICAS CON TAXONOMĂAS\r\n * ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n * \r\n * Estructura URLs:\r\n *   â fichas.es/infantil/3-anos/matematicas/numero-1/\r\n *   â fichas.es/primaria/1-primaria/lengua/consonante-m/\r\n * \r\n * Fallback automĂĄtico si falta taxonomĂ­a:\r\n *   â ïž fichas.es/ficha/slug-sin-taxonomias/\r\n * \r\n * VersiĂłn: 1.0 PRODUCCIĂN\r\n * Fecha: 3 febrero 2026\r\n * ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n */\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 1. MODIFICAR ESTRUCTURA REWRITE DEL CPT \'FICHA\'\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_filter(\'register_post_type_args\', \'fichas_hierarchical_rewrite\', 10, 2);\r\nfunction fichas_hierarchical_rewrite($args, $post_type) {\r\n    if (\'ficha\' !== $post_type) {\r\n        return $args;\r\n    }\r\n    \r\n    $args[\'rewrite\'] = array(\r\n        \'slug\'         => \'%nivel-educativo%/%curso%/%asignatura%\',\r\n        \'with_front\'   => false,\r\n        \'hierarchical\' => false\r\n    );\r\n    \r\n    return $args;\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 2. GENERAR URL JERĂRQUICA REAL (reemplazar placeholders)\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_filter(\'post_type_link\', \'fichas_build_hierarchical_url\', 10, 2);\r\nfunction fichas_build_hierarchical_url($post_link, $post) {\r\n    if (\'ficha\' !== $post->post_type) {\r\n        return $post_link;\r\n    }\r\n    \r\n    // Obtener taxonomĂ­as\r\n    $nivel      = wp_get_object_terms($post->ID, \'nivel-educativo\');\r\n    $curso      = wp_get_object_terms($post->ID, \'curso\');\r\n    $asignatura = wp_get_object_terms($post->ID, \'asignatura\');\r\n    \r\n    // Validar existencia\r\n    $nivel_ok      = (!is_wp_error($nivel) && !empty($nivel));\r\n    $curso_ok      = (!is_wp_error($curso) && !empty($curso));\r\n    $asignatura_ok = (!is_wp_error($asignatura) && !empty($asignatura));\r\n    \r\n    // Fallback si falta alguna taxonomĂ­a\r\n    if (!$nivel_ok || !$curso_ok || !$asignatura_ok) {\r\n        return home_url(\'/ficha/\' . $post->post_name . \'/\');\r\n    }\r\n    \r\n    // Construir URL jerĂĄrquica\r\n    return home_url(sprintf(\r\n        \'/%s/%s/%s/%s/\',\r\n        $nivel[0]->slug,\r\n        $curso[0]->slug,\r\n        $asignatura[0]->slug,\r\n        $post->post_name\r\n    ));\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 3. REGLAS DE REWRITE PARA WORDPRESS\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_action(\'init\', \'fichas_add_custom_rewrite_rules\', 20);\r\nfunction fichas_add_custom_rewrite_rules() {\r\n    $niveles = get_terms(array(\r\n        \'taxonomy\'   => \'nivel-educativo\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    $cursos = get_terms(array(\r\n        \'taxonomy\'   => \'curso\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    $asignaturas = get_terms(array(\r\n        \'taxonomy\'   => \'asignatura\',\r\n        \'hide_empty\' => false,\r\n        \'fields\'     => \'slugs\'\r\n    ));\r\n    \r\n    if (is_wp_error($niveles) || empty($niveles) ||\r\n        is_wp_error($cursos) || empty($cursos) ||\r\n        is_wp_error($asignaturas) || empty($asignaturas)) {\r\n        return;\r\n    }\r\n    \r\n    $niveles_escaped     = array_map(\'preg_quote\', $niveles);\r\n    $cursos_escaped      = array_map(\'preg_quote\', $cursos);\r\n    $asignaturas_escaped = array_map(\'preg_quote\', $asignaturas);\r\n    \r\n    $niveles_pattern     = \'(\' . implode(\'|\', $niveles_escaped) . \')\';\r\n    $cursos_pattern      = \'(\' . implode(\'|\', $cursos_escaped) . \')\';\r\n    $asignaturas_pattern = \'(\' . implode(\'|\', $asignaturas_escaped) . \')\';\r\n    \r\n    // Regla principal: /nivel/curso/asignatura/slug/\r\n    add_rewrite_rule(\r\n        \'^\' . $niveles_pattern . \'/\' . $cursos_pattern . \'/\' . $asignaturas_pattern . \'/([^/]+)/?$\',\r\n        \'index.php?ficha=$matches[4]\',\r\n        \'top\'\r\n    );\r\n    \r\n    // Regla fallback: /ficha/slug/\r\n    add_rewrite_rule(\r\n        \'^ficha/([^/]+)/?$\',\r\n        \'index.php?ficha=$matches[1]\',\r\n        \'bottom\'\r\n    );\r\n}\r\n\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\n// 4. AUTO-FLUSH REWRITE RULES AL MODIFICAR TAXONOMĂAS\r\n// ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ\r\nadd_action(\'created_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nadd_action(\'edited_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nadd_action(\'delete_term\', \'fichas_schedule_flush_rules\', 10, 3);\r\nfunction fichas_schedule_flush_rules($term_id, $tt_id, $taxonomy) {\r\n    $target_taxonomies = array(\'nivel-educativo\', \'curso\', \'asignatura\');\r\n    \r\n    if (in_array($taxonomy, $target_taxonomies)) {\r\n        set_transient(\'fichas_needs_flush_rules\', 1, 60);\r\n    }\r\n}\r\n\r\nadd_action(\'init\', \'fichas_maybe_flush_rules\', 999);\r\nfunction fichas_maybe_flush_rules() {\r\n    if (get_transient(\'fichas_needs_flush_rules\')) {\r\n        flush_rewrite_rules(false);\r\n        delete_transient(\'fichas_needs_flush_rules\');\r\n    }\r\n}\r\n','Fichas - URLs JerĂĄrquicas','','publish','closed','closed','','fichas-urls-jerarquicas','','','2026-02-03 13:59:09','2026-02-03 13:59:09','',0,'http://localhost:8080/?post_type=wpcode&#038;p=367',0,'wpcode','',0),
