(2480,131,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n  <div class=\"instrucciones\">ÂĄHola pequeĂ±o matemĂĄtico! Vamos a contar juntos. Mira bien los dibujos y elige la respuesta correcta. ÂĄTĂș puedes hacerlo!</div>\r\n  <div class=\"contenedor-preguntas\">\r\n    \r\n    <!-- Ejercicio 1: SelecciĂłn mĂșltiple -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3\">\r\n      <div class=\"pregunta\">ÂżCuĂĄntas estrellas hay?</div>\r\n      <div class=\"visual\">â­ â­ â­</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2\">2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3\">3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 2: SelecciĂłn mĂșltiple -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"5\">\r\n      <div class=\"pregunta\">Cuenta los corazones</div>\r\n      <div class=\"visual\">â€ïž â€ïž â€ïž â€ïž â€ïž</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"4\">4</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5\">5</button>\r\n        <button class=\"opcion-btn\" data-valor=\"6\">6</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 3: Verdadero/Falso -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n      <div class=\"pregunta\">ÂżHay 7 cĂ­rculos?</div>\r\n      <div class=\"visual\">â â â â â â â</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"verdadero\">SĂ­</button>\r\n        <button class=\"opcion-btn\" data-valor=\"falso\">No</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 4: SelecciĂłn mĂșltiple -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"1\">\r\n      <div class=\"pregunta\">ÂżCuĂĄntos triĂĄngulos ves?</div>\r\n      <div class=\"visual\">âČ<