(2522,133,'descripcion','<p>Esta <strong>ficha interactiva</strong> estĂĄ diseĂ±ada para que los alumnos de <strong>1Âș Primaria</strong> refuercen el ordenamiento de los <strong>nĂșmeros del 1 al 10</strong>. A travĂ©s de ejercicios visuales y progresivos, los estudiantes aprenderĂĄn a identificar la secuencia correcta de menor a mayor de forma divertida y motivadora.</p>\r\n\r\n<p>Los 12 ejercicios incluyen nĂșmeros consecutivos y no consecutivos para aumentar gradualmente la dificultad. Cada actividad presenta sĂ­mbolos coloridos y contextos familiares que facilitan la comprensiĂłn. Los alumnos deberĂĄn elegir entre tres opciones la secuencia correcta, desarrollando asĂ­ su <strong>sentido numĂ©rico</strong> segĂșn los objetivos del currĂ­culo LOMLOE.</p>\r\n\r\n<p>Esta actividad forma parte de nuestras <a href=\"/primaria/1-primaria/matematicas/\">fichas de matemĂĄticas para 1Âș Primaria</a>, especialmente diseĂ±adas para estudiantes de 6-7 aĂ±os. Encuentra mĂĄs recursos educativos en nuestra secciĂłn de <a href=\"/primaria/\">EducaciĂłn Primaria</a> para complementar el aprendizaje de tus alumnos.</p>'),
(2523,133,'_contenido_ficha_html','field_contenido_ficha_html'),
(2524,133,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n  <div class=\"instrucciones\">ÂĄHola pequeĂ±o matemĂĄtico! Vamos a ordenar nĂșmeros del mĂĄs pequeĂ±o al mĂĄs grande. ÂĄLee bien y elige la respuesta correcta!</div>\r\n  <div class=\"contenedor-preguntas\">\r\n    \r\n    <!-- Ejercicio 1: NĂșmeros consecutivos (fĂĄcil) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3, 4, 5\">\r\n      <div class=\"pregunta\">Ordena estos nĂșmeros de menor a mayor:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">5 - 3 - 4</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"5, 4, 3\">5, 4, 3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4, 3, 5\">4, 3, 5</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3, 4, 5\">3, 4, 5</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 2: Saltos grandes -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"1, 6, 9\">\r\n      <div class=\"pregunta\">ÂżCuĂĄl es el orden correcto de menor a mayor?</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">9 - 1 - 6</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"9, 6, 1\">9, 6, 1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"1, 6, 9\">1, 6, 9</button>\r\n        <button class=\"opcion-btn\" data-valor=\"6, 1, 9\">6, 1, 9</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 3: Tres nĂșmeros no consecutivos -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"2, 7, 8\">\r\n      <div class=\"pregunta\">Ordena del mĂĄs pequeĂ±o al mĂĄs grande:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">8 - 2 - 7</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"8, 7, 2\">8, 7, 2</button>\r\n        <button class=\"opcion-btn\" data-valor=\"2, 8, 7\">2, 8, 7</button>\r\n        <button class=\"opcion-btn\" data-valor=\"2, 7, 8\">2, 7, 8</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 4: Con el 10 -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"1, 5, 10\">\r\n      <div class=\"pregunta\">ÂżEn quĂ© orden van estos nĂșmeros?</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">10 - 1 - 5</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"10, 5, 1\">10, 5, 1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"1, 5, 10\">1, 5, 10</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5, 1, 10\">5, 1, 10</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 5: NĂșmeros cercanos (mĂĄs difĂ­cil) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"4, 6, 7\">\r\n      <div class=\"pregunta\">Ordena de menor a mayor:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">6 - 4 - 7</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"6, 7, 4\">6, 7, 4</button>\r\n        <button class=\"opcion-btn\" data-valor=\"4, 6, 7\">4, 6, 7</button>\r\n        <button class=\"opcion-btn\" data-valor=\"7, 4, 6\">7, 4, 6</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 6: Con nĂșmeros bajos -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"3, 8, 9\">\r\n      <div class=\"pregunta\">ÂżCuĂĄl es la secuencia correcta?</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">8 - 3 - 9</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"8, 9, 3\">8, 9, 3</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3, 8, 9\">3, 8, 9</button>\r\n        <button class=\"opcion-btn\" data-valor=\"9, 8, 3\">9, 8, 3</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 7: Incluye el 0 (desafĂ­o) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"0, 2, 6\">\r\n      <div class=\"pregunta\">Ordena del mĂĄs pequeĂ±o al mĂĄs grande:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">2 - 6 - 0</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"2, 0, 6\">2, 0, 6</button>\r\n        <button class=\"opcion-btn\" data-valor=\"0, 2, 6\">0, 2, 6</button>\r\n        <button class=\"opcion-btn\" data-valor=\"6, 2, 0\">6, 2, 0</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 8: Cuatro nĂșmeros (aumento dificultad) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"1, 3, 7, 10\">\r\n      <div class=\"pregunta\">Ordena estos cuatro nĂșmeros de menor a mayor:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">10 - 1 - 7 - 3</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"10, 7, 3, 1\">10, 7, 3, 1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"1, 3, 7, 10\">1, 3, 7, 10</button>\r\n        <button class=\"opcion-btn\" data-valor=\"3, 1, 10, 7\">3, 1, 10, 7</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 9: NĂșmeros consecutivos cercanos -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"5, 7, 9\">\r\n      <div class=\"pregunta\">ÂżEn quĂ© orden van?</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">7 - 9 - 5</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"7, 9, 5\">7, 9, 5</button>\r\n        <button class=\"opcion-btn\" data-valor=\"9, 7, 5\">9, 7, 5</button>\r\n        <button class=\"opcion-btn\" data-valor=\"5, 7, 9\">5, 7, 9</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 10: Con el 0 en medio -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"0, 4, 8\">\r\n      <div class=\"pregunta\">Ordena de menor a mayor:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">4 - 8 - 0</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"4, 0, 8\">4, 0, 8</button>\r\n        <button class=\"opcion-btn\" data-valor=\"0, 4, 8\">0, 4, 8</button>\r\n        <button class=\"opcion-btn\" data-valor=\"8, 4, 0\">8, 4, 0</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 11: Cuatro nĂșmeros con 0 -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"0, 2, 5, 9\">\r\n      <div class=\"pregunta\">Ordena estos cuatro nĂșmeros:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">5 - 0 - 9 - 2</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"5, 2, 9, 0\">5, 2, 9, 0</button>\r\n        <button class=\"opcion-btn\" data-valor=\"0, 2, 5, 9\">0, 2, 5, 9</button>\r\n        <button class=\"opcion-btn\" data-valor=\"2, 0, 5, 9\">2, 0, 5, 9</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 12: DesafĂ­o final - cinco nĂșmeros -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"1, 3, 5, 8, 10\">\r\n      <div class=\"pregunta\">Ordena estos cinco nĂșmeros de menor a mayor:</div>\r\n      <div class=\"visual\" style=\"font-size: 2em;\">8 - 1 - 10 - 5 - 3</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"1, 3, 5, 8, 10\">1, 3, 5, 8, 10</button>\r\n        <button class=\"opcion-btn\" data-valor=\"10, 8, 5, 3, 1\">10, 8, 5, 3, 1</button>\r\n        <button class=\"opcion-btn\" data-valor=\"1, 5, 3, 8, 10\">1, 5, 3, 8, 10</button>\r\n      </div>\r\n    </div>\r\n    \r\n  </div>\r\n  <div class=\"acciones\">\r\n    <button class=\"btn-comprobar\">ÂĄYa terminĂ©! Comprobar respuestas</button>\r\n    <button class=\"btn-descargar-pdf\" id=\"descargarPDF_MAT003\">âŹïž Descargar PDF</button>\r\n  </div>\r\n  <div class=\"feedback\"></div>\r\n</div>\r\n'),
