(2544,134,'descripcion','<p>Esta <strong>ficha interactiva</strong> estĂĄ diseĂ±ada para que los niĂ±os de 6-7 aĂ±os aprendan a comparar nĂșmeros del 1 al 10 usando los sĂ­mbolos matemĂĄticos mayor que (>), menor que (<) e igual (=). Los ejercicios combinan representaciones visuales con sĂ­mbolos numĂ©ricos para facilitar la comprensiĂłn.</p>\r\n\r\n<p>Perfectamente adaptada al currĂ­culo de <strong>1Âș Primaria</strong>, la actividad incluye 12 ejercicios variados que trabajan el sentido numĂ©rico de forma progresiva. Los estudiantes podrĂĄn elegir entre opciones mĂșltiples y validar comparaciones, reforzando asĂ­ su comprensiĂłn de las relaciones numĂ©ricas bĂĄsicas.</p>\r\n\r\n<p>Forma parte de nuestro completo programa de <a href=\"/primaria/1-primaria/matematicas/\">matemĂĄticas para 1Âș de Primaria</a>, donde encontrarĂĄs mĂĄs recursos similares. Visita nuestra secciĂłn de <a href=\"/primaria/\">EducaciĂłn Primaria</a> para acceder a fichas de todos los cursos y materias.</p>'),
(2545,134,'_contenido_ficha_html','field_contenido_ficha_html'),
(2546,134,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n  <div class=\"instrucciones\">ÂĄVamos a comparar nĂșmeros! Mira bien cada pareja de nĂșmeros y elige el sĂ­mbolo correcto: mayor que (>), menor que (<) o igual (=).</div>\r\n  <div class=\"contenedor-preguntas\">\r\n    \r\n    <!-- Ejercicio 1: ComparaciĂłn bĂĄsica -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"<\">\r\n      <div class=\"pregunta\">ÂżQuĂ© sĂ­mbolo va entre estos nĂșmeros?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">3 __ 7</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 2: Mayor que -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\">\">\r\n      <div class=\"pregunta\">Completa la comparaciĂłn:</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">9 __ 4</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 3: Igual -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"=\">\r\n      <div class=\"pregunta\">ÂżQuĂ© sĂ­mbolo falta?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">5 __ 5</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 4: Verdadero/Falso -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n      <div class=\"pregunta\">ÂżEs correcto que 2 < 6?</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button>\r\n        <button class=\"opcion-btn\" data-valor=\"falso\">Falso</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 5: Con el nĂșmero 10 -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"<\">\r\n      <div class=\"pregunta\">ÂżQuĂ© sĂ­mbolo necesitas?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">1 __ 10</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 6: Verdadero/Falso (trampa) -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"falso\">\r\n      <div class=\"pregunta\">ÂżEs verdad que 8 = 3?</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button>\r\n        <button class=\"opcion-btn\" data-valor=\"falso\">Falso</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 7: Mayor que -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\">\">\r\n      <div class=\"pregunta\">Completa:</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">6 __ 2</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 8: Menor que -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"<\">\r\n      <div class=\"pregunta\">ÂżQuĂ© sĂ­mbolo va aquĂ­?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">4 __ 9</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 9: Verdadero/Falso -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n      <div class=\"pregunta\">ÂżEs correcto que 7 > 1?</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"verdadero\">Verdadero</button>\r\n        <button class=\"opcion-btn\" data-valor=\"falso\">Falso</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 10: Igual con nĂșmeros altos -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"=\">\r\n      <div class=\"pregunta\">ÂżQuĂ© sĂ­mbolo falta?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">8 __ 8</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 11: Identificar mayor -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"10\">\r\n      <div class=\"pregunta\">ÂżQuĂ© nĂșmero es mayor?</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">7 o 10</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"7\">7</button>\r\n        <button class=\"opcion-btn\" data-valor=\"10\">10</button>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Ejercicio 12: Mayor que con nĂșmeros altos -->\r\n    <div class=\"bloque-ejercicio\" data-respuesta-correcta=\">\">\r\n      <div class=\"pregunta\">Completa la comparaciĂłn:</div>\r\n      <div class=\"visual\" style=\"font-size: 2.5em;\">10 __ 7</div>\r\n      <div class=\"opciones\">\r\n        <button class=\"opcion-btn\" data-valor=\"<\"><</button>\r\n        <button class=\"opcion-btn\" data-valor=\">\">></button>\r\n        <button class=\"opcion-btn\" data-valor=\"=\">=</button>\r\n      </div>\r\n    </div>\r\n    \r\n  </div>\r\n  <div class=\"acciones\">\r\n    <button class=\"btn-comprobar\">ÂĄYa terminĂ©! Comprobar respuestas</button>\r\n    <button class=\"btn-descargar-pdf\" id=\"descargarPDF_MAT004\">âŹïž Descargar PDF</button>\r\n  </div>\r\n  <div class=\"feedback\"></div>\r\n</div>\r\n'),
