(2606,137,'contenido_ficha_html','<div class=\"ficha-educativa\">\r\n    <div class=\"instrucciones\">???? <strong>Instrucciones:</strong> Observa el dibujo del cuerpo humano. Identifica cada parte seĂ±alada y selecciona el nombre correcto.</div>\r\n\r\n    <div class=\"contenedor-preguntas\">\r\n        <!-- Imagen principal centrada -->\r\n        <div style=\"grid-column: 1 / -1; text-align: center; margin-bottom: 30px;\">\r\n            <img src=\"http://localhost:8080/wp-content/uploads/2026/01/partesdelcuerpo.jpg\" \r\n                 alt=\"Partes del cuerpo humano - Diagrama educativo\" \r\n                 style=\"max-width: 100%; height: auto; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.1);\">\r\n        </div>\r\n\r\n        <!-- Ejercicio 1 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Cabeza\">\r\n            <div class=\"pregunta\">1ïžâŁ ÂżQuĂ© parte del cuerpo estĂĄ seĂ±alada con el nĂșmero 1?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Cabeza\">Cabeza</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Tronco\">Tronco</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Brazo\">Brazo</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 2 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Tronco\">\r\n            <div class=\"pregunta\">2ïžâŁ El nĂșmero 2 seĂ±ala...</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Pierna\">Pierna</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Tronco\">Tronco</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Cabeza\">Cabeza</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 3 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Brazo\">\r\n            <div class=\"pregunta\">3ïžâŁ ÂżQuĂ© parte estĂĄ marcada con el 3?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Mano\">Mano</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Brazo\">Brazo</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Pie\">Pie</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 4 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Pierna\">\r\n            <div class=\"pregunta\">4ïžâŁ El punto 4 indica la...</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Pierna\">Pierna</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Mano\">Mano</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Cabeza\">Cabeza</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 5 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Mano\">\r\n            <div class=\"pregunta\">5ïžâŁ ÂżQuĂ© parte del cuerpo seĂ±ala el nĂșmero 5?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Pie\">Pie</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Brazo\">Brazo</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Mano\">Mano</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 6 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Pie\">\r\n            <div class=\"pregunta\">6ïžâŁ El nĂșmero 6 marca el...</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Pie\">Pie</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Tronco\">Tronco</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Pierna\">Pierna</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 7 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n            <div class=\"pregunta\">7ïžâŁ ÂżTenemos dos brazos?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"verdadero\">SĂ­</button>\r\n                <button class=\"opcion-btn\" data-valor=\"falso\">No</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 8 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"La cabeza\">\r\n            <div class=\"pregunta\">8ïžâŁ ÂżQuĂ© parte del cuerpo estĂĄ mĂĄs arriba?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"La cabeza\">La cabeza</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Los pies\">Los pies</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Las manos\">Las manos</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 9 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Los pies\">\r\n            <div class=\"pregunta\">9ïžâŁ ÂżCon quĂ© parte del cuerpo caminamos?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Las manos\">Las manos</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Los brazos\">Los brazos</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Los pies\">Los pies</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 10 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"Las manos\">\r\n            <div class=\"pregunta\">???? ÂżCon quĂ© parte escribimos?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"Los pies\">Los pies</button>\r\n                <button class=\"opcion-btn\" data-valor=\"Las manos\">Las manos</button>\r\n                <button class=\"opcion-btn\" data-valor=\"La cabeza\">La cabeza</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 11 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n            <div class=\"pregunta\">1ïžâŁ1ïžâŁ ÂżEl tronco estĂĄ entre la cabeza y las piernas?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"verdadero\">SĂ­</button>\r\n                <button class=\"opcion-btn\" data-valor=\"falso\">No</button>\r\n            </div>\r\n        </div>\r\n\r\n        <!-- Ejercicio 12 -->\r\n        <div class=\"bloque-ejercicio\" data-respuesta-correcta=\"verdadero\">\r\n            <div class=\"pregunta\">1ïžâŁ2ïžâŁ ÂżTenemos dos piernas?</div>\r\n            <div class=\"opciones\">\r\n                <button class=\"opcion-btn\" data-valor=\"verdadero\">SĂ­</button>\r\n                <button class=\"opcion-btn\" data-valor=\"falso\">No</button>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"acciones\">\r\n        <button class=\"btn-comprobar\">ÂĄYa terminĂ©! Comprobar respuestas</button>\r\n        <button class=\"btn-descargar-pdf\" id=\"descargarPDF_CME001\">âŹïž Descargar PDF</button>\r\n    </div>\r\n\r\n    <div class=\"feedback\"></div>\r\n</div>'),
