va .bloque-ejercicio {\n  background: white !important;\n  padding: 20px !important;\n  border-radius: 12px !important;\n  border: 2px solid #E0E0E0 !important;\n  box-shadow: 2px 2px 5px rgba(0,0,0,0.1) !important;\n  text-align: center !important;\n}\n\n.ficha-educativa .bloque-ejercicio.correcto {\n  border: 4px solid #28a745 !important;\n  background: #d4edda !important;\n}\n\n.ficha-educativa .bloque-ejercicio.incorrecto {\n  border: 4px solid #ffc107 !important;\n  background: #fff3cd !important;\n}\n\n.ficha-educativa .pregunta {\n  font-size: 1.3em !important;\n  color: #011627 !important;\n  margin-bottom: 15px !important;\n  font-weight: bold !important;\n  text-align: center !important;\n}\n\n.ficha-educativa .visual {\n  font-size: 2.5em !important;\n  text-align: center !important;\n  margin: 15px 0 !important;\n}\n\n.ficha-educativa .opciones {\n  display: flex !important;\n  flex-wrap: wrap !important;\n  gap: 15px !important;\n  justify-content: center !important;\n  margin-top: 15px !important;\n}\n\n.ficha-educativa .opcion-btn {\n  padding: 20px 30px !important;\n  font-size: 1.5em !important;\n  font-family: inherit !important;\n  border: 3px solid #2EC4B6 !important;\n  background: white !important;\n  color: #011627 !important;\n  border-radius: 25px !important;\n  cursor: pointer !important;\n  transition: all 0.3s ease !important;\n  min-width: 80px !important;\n  font-weight: bold !important;\n}\n\n.ficha-educativa .opcion-btn:hover,\n.ficha-educativa .opcion-btn:focus {\n  transform: scale(1.1) !important;\n  outline: 3px solid #FF9F1C !important;\n}\n\n.ficha-educativa .opcion-btn.seleccionada {\n  background: #2EC4B6 !important;\n  color: white !important;\n  box-shadow: 4px 4px 0px #011627 !important;\n}\n\n.ficha-educativa .opcion-btn.correcto {\n  border: 4px solid #28a745 !important;\n  background: #d4edda !important;\n}\n\n.ficha-educativa .opcion-btn.incorrecto {\n  border: 4px solid #ffc107 !important;\n  background: #fff3cd !important;\n}\n\n.ficha-educativa .btn-comprobar {\n  width: 100% !important;\n  padding: 20px !important;\n  font-size: 1.8em !important;\n  font-family: inherit !important;\n  background: #FF9F1C !important;\n  color: white !important;\n  border: none !important;\n  border-radius: 25px !important;\n  cursor: pointer !important;\n  font-weight: bold !important;\n  margin: 20px 0 !important;\n  transition: all 0.3s ease !important;\n}\n\n.ficha-educativa .btn-comprobar:hover {\n  background: #FFBF69 !important;\n  transform: scale(1.02) !important;\n}\n\n.ficha-educativa .btn-comprobar:disabled {\n  background: #ccc !important;\n  cursor: not-allowed !important;\n}\n\n.ficha-educativa .feedback {\n  font-size: 1.6em !important;\n  padding: 20px !important;\n  border-radius: 15px !important;\n  text-align: center !important;\n  font-weight: bold !important;\n  margin-top: 20px !important;\n  display: none !important;\n}\n\n.ficha-educativa .feedback.exito {\n  background: #D4EDDA !important;\n  color: #155724 !important;\n  display: block !important;\n}\n\n.ficha-educativa .feedback.mejorar {\n  background: #FFF3CD !important;\n  color: #856404 !important;\n  display: block !important;\n}\n\n\n\n','asap','','publish','closed','closed','','asap','','','2026-01-14 12:37:45','2026-01-14 12:37:45','',0,'http://localhost:8080/asap/',0,'custom_css','',0),
