osition: fixed;\n  font-size: 30px;\n  animation: caer 3s ease-in-out forwards;\n  pointer-events: none;\n}\n','asap','','inherit','closed','closed','','18-revision-v1','','','2026-01-14 12:10:20','2026-01-14 12:10:20','',18,'http://localhost:8080/?p=19',0,'revision','',0),
