ransition: all 0.3s ease;\n  min-width: 80px;\n  font-weight: bold;\n}\n\n.ficha-educativa .opcion-btn:hover,\n.ficha-educativa .opcion-btn:focus {\n  transform: scale(1.1);\n  outline: 3px solid #FF9F1C;\n}\n\n.ficha-educativa .opcion-btn.seleccionado {\n  background: #2EC4B6;\n  color: white;\n  box-shadow: 4px 4px 0px #011627;\n}\n\n.ficha-educativa .opcion-btn.correcto {\n  border: 4px solid #28a745;\n  background: #d4edda;\n}\n\n.ficha-educativa .opcion-btn.incorrecto {\n  border: 4px solid #ffc107;\n  background: #fff3cd;\n}\n\n.ficha-educativa .btn-comprobar {\n  width: 100%;\n  padding: 20px;\n  font-size: 1.8em;\n  font-family: inherit;\n  background: #FF9F1C;\n  color: white;\n  border: none;\n  border-radius: 25px;\n  cursor: pointer;\n  font-weight: bold;\n  margin: 20px 0;\n  transition: all 0.3s ease;\n}\n\n.ficha-educativa .btn-comprobar:hover {\n  background: #FFBF69;\n  transform: scale(1.02);\n}\n\n.ficha-educativa .btn-comprobar:focus {\n  outline: 3px solid #FF9F1C;\n}\n\n.ficha-educativa .feedback {\n  font-size: 1.6em;\n  padding: 20px;\n  border-radius: 15px;\n  text-align: center;\n  font-weight: bold;\n  margin-top: 20px;\n  display: none;\n}\n\n.ficha-educativa .feedback.exito {\n  background: #D4EDDA;\n  color: #155724;\n  display: block;\n}\n\n.ficha-educativa .feedback.mejorar {\n  background: #FFF3CD;\n  color: #856404;\n  display: block;\n}\n\n@keyframes caer {\n  0% {\n    transform: translateY(-100px) rotate(0deg);\n    opacity: 1;\n  }\n  100% {\n    transform: translateY(100vh) rotate(360deg);\n    opacity: 0;\n  }\n}\n\n.ficha-educativa .estrella {\n  position: fixed;\n  font-size: 30px;\n  animation: caer 3s ease-in-out forwards;\n  pointer-events: none;\n}\n\n','asap','','inherit','closed','closed','','18-revision-v1','','','2026-01-14 12:20:02','2026-01-14 12:20:02','',18,'http://localhost:8080/?p=25',0,'revision','',0),
