(64,1,'2026-01-14 16:57:14','0000-00-00 00:00:00','add_action(\'admin_init\', function () {\r\n    // Redirect any user trying to access comments page\r\n    global $pagenow;\r\n    \r\n    if ($pagenow === \'edit-comments.php\') {\r\n        wp_safe_redirect(admin_url());\r\n        exit;\r\n    }\r\n\r\n    // Remove comments metabox from dashboard\r\n    remove_meta_box(\'dashboard_recent_comments\', \'dashboard\', \'normal\');\r\n\r\n    // Disable support for comments and trackbacks in post types\r\n    foreach (get_post_types() as $post_type) {\r\n        if (post_type_supports($post_type, \'comments\')) {\r\n            remove_post_type_support($post_type, \'comments\');\r\n            remove_post_type_support($post_type, \'trackbacks\');\r\n        }\r\n    }\r\n});\r\n\r\n// Close comments on the front-end\r\nadd_filter(\'comments_open\', \'__return_false\', 20, 2);\r\nadd_filter(\'pings_open\', \'__return_false\', 20, 2);\r\n\r\n// Hide existing comments\r\nadd_filter(\'comments_array\', \'__return_empty_array\', 10, 2);\r\n\r\n// Remove comments page in menu\r\nadd_action(\'admin_menu\', function () {\r\n    remove_menu_page(\'edit-comments.php\');\r\n});\r\n\r\n// Remove comments links from admin bar\r\nadd_action(\'init\', function () {\r\n    if (is_admin_bar_showing()) {\r\n        remove_action(\'admin_bar_menu\', \'wp_admin_bar_comments_menu\', 60);\r\n    }\r\n});','Desactivar completamente los comentarios','','draft','closed','closed','','','','','2026-01-14 16:57:14','0000-00-00 00:00:00','',0,'http://localhost:8080/?post_type=wpcode&p=64',0,'wpcode','',0),
(65,1,'2026-01-14 16:58:27','2026-01-14 16:58:27','// ============================================================================\r\n// BLOQUES ACF PARA GUTENBERG - FICHAS\r\n// ============================================================================\r\n\r\nadd_action(\'acf/init\', \'registrar_bloques_ficha\');\r\nfunction registrar_bloques_ficha() {\r\n    \r\n    // Verificar que existe la funciĂłn\r\n    if( function_exists(\'acf_register_block_type\') ) {\r\n        \r\n        // BLOQUE 1: Cabecera con metadatos\r\n        acf_register_block_type(array(\r\n            \'name\'              => \'ficha-cabecera\',\r\n            \'title\'             => \'Cabecera Ficha\',\r\n            \'description\'       => \'Muestra edad, tiempo y metadatos\',\r\n            \'render_callback\'   => \'render_bloque_ficha_cabecera\',\r\n            \'category\'          => \'fichas\',\r\n            \'icon\'              => \'id-alt\',\r\n            \'keywords\'          => array(\'ficha\', \'cabecera\', \'metadatos\'),\r\n            \'supports\'          => array(\'align\' => false),\r\n        ));\r\n        \r\n        // BLOQUE 2: Contenido HTML\r\n        acf_register_block_type(array(\r\n            \'name\'              => \'ficha-contenido-html\',\r\n            \'title\'             => \'Contenido Ficha HTML\',\r\n            \'description\'       => \'Muestra el contenido interactivo de la ficha\',\r\n            \'render_callback\'   => \'render_bloque_ficha_contenido\',\r\n            \'category\'          => \'fichas\',\r\n            \'icon\'              => \'media-code\',\r\n            \'keywords\'          => array(\'ficha\', \'contenido\', \'html\'),\r\n        ));\r\n        \r\n        // BLOQUE 3: Objetivos\r\n        acf_register_block_type(array(\r\n            \'name\'              => \'ficha-objetivos\',\r\n            \'title\'             => \'Objetivos de Aprendizaje\',\r\n            \'description\'       => \'Muestra los objetivos de la ficha\',\r\n            \'render_callback\'   => \'render_bloque_ficha_objetivos\',\r\n            \'category\'          => \'fichas\',\r\n            \'icon\'              => \'yes-alt\',\r\n            \'keywords\'          => array(\'ficha\', \'objetivos\'),\r\n        ));\r\n        \r\n        // BLOQUE 4: Instrucciones\r\n        acf_register_block_type(array(\r\n            \'name\'              => \'ficha-instrucciones\',\r\n            \'title\'             => \'Instrucciones\',\r\n            \'description\'       => \'Muestra las instrucciones de la ficha\',\r\n            \'render_callback\'   => \'render_bloque_ficha_instrucciones\',\r\n            \'category\'          => \'fichas\',\r\n            \'icon\'              => \'list-view\',\r\n            \'keywords\'          => array(\'ficha\', \'instrucciones\'),\r\n        ));\r\n    }\r\n}\r\n\r\n// Crear categorĂ­a personalizada para los bloques\r\nadd_filter(\'block_categories_all\', \'agregar_categoria_bloques_fichas\', 10, 2);\r\nfunction agregar_categoria_bloques_fichas($categories) {\r\n    return array_merge(\r\n        array(\r\n            array(\r\n                \'slug\'  => \'fichas\',\r\n                \'title\' => \'Fichas Educativas\',\r\n                \'icon\'  => \'welcome-learn-more\',\r\n            ),\r\n        ),\r\n        $categories\r\n    );\r\n}\r\n\r\n// FUNCIONES DE RENDERIZADO\r\n\r\n// Bloque 1: Cabecera\r\nfunction render_bloque_ficha_cabecera($block, $content = \'\', $is_preview = false) {\r\n    $edad = get_field(\'edad_recomendada\');\r\n    $tiempo = get_field(\'tiempo_estimado\');\r\n    \r\n    $nivel = get_the_terms(get_the_ID(), \'nivel-educativo\');\r\n    $curso = get_the_terms(get_the_ID(), \'curso\');\r\n    $asignatura = get_the_terms(get_the_ID(), \'asignatura\');\r\n    $dificultad = get_the_terms(get_the_ID(), \'dificultad\');\r\n    ?>\r\n    \r\n    <div class=\"ficha-header\">\r\n        <div class=\"ficha-breadcrumb\">\r\n            <?php if ($nivel && !is_wp_error($nivel)) : ?>\r\n                <span class=\"badge badge-nivel\"><?php echo esc_html($nivel[0]->name); ?></span>\r\n            <?php endif; ?>\r\n            \r\n            <?php if ($curso && !is_wp_error($curso)) : ?>\r\n                <span class=\"badge badge-curso\"><?php echo esc_html($curso[0]->name); ?></span>\r\n            <?php endif; ?>\r\n            \r\n            <?php if ($asignatura && !is_wp_error($asignatura)) : ?>\r\n                <span class=\"badge badge-asignatura\"><?php echo esc_html($asignatura[0]->name); ?></span>\r\n            <?php endif; ?>\r\n        </div>\r\n        \r\n        <div class=\"ficha-meta\">\r\n            <?php if ($edad) : ?>\r\n                <span class=\"meta-item\">\r\n                    <strong>Edad:</strong> <?php echo esc_html($edad); ?>\r\n                </span>\r\n            <?php endif; ?>\r\n            \r\n            <?php if ($tiempo) : ?>\r\n                <span class=\"meta-item\">\r\n                    <strong>Tiempo:</strong> <?php echo esc_html($tiempo); ?> minutos\r\n                </span>\r\n            <?php endif; ?>\r\n            \r\n            <?php if ($dificultad && !is_wp_error($dificultad)) : ?>\r\n                <span class=\"meta-item\">\r\n                    <strong>Dificultad:</strong> <?php echo esc_html($dificultad[0]->name); ?>\r\n                </span>\r\n            <?php endif; ?>\r\n        </div>\r\n    </div>\r\n    <?php\r\n}\r\n\r\n// Bloque 2: Contenido HTML\r\nfunction render_bloque_ficha_contenido($block, $content = \'\', $is_preview = false) {\r\n    $descripcion = get_field(\'descripcion\');\r\n    $contenido_html = get_field(\'contenido_ficha_html\');\r\n    ?>\r\n    \r\n    <?php if ($descripcion) : ?>\r\n        <div class=\"ficha-descripcion\">\r\n            <?php echo wpautop($descripcion); ?>\r\n        </div>\r\n    <?php endif; ?>\r\n    \r\n    <?php if ($contenido_html) : ?>\r\n        <div class=\"ficha-contenido-html\">\r\n            <?php echo $contenido_html; ?>\r\n        </div>\r\n    <?php endif; ?>\r\n    <?php\r\n}\r\n\r\n// Bloque 3: Objetivos\r\nfunction render_bloque_ficha_objetivos($block, $content = \'\', $is_preview = false) {\r\n    $objetivos = get_field(\'objetivos\');\r\n    if ($objetivos) : ?>\r\n        <div class=\"ficha-card ficha-objetivos\">\r\n            <h3>???? Objetivos de Aprendizaje</h3>\r\n            <div class=\"objetivos-contenido\">\r\n                <?php echo nl2br(esc_html($objetivos)); ?>\r\n            </div>\r\n        </div>\r\n    <?php endif;\r\n}\r\n\r\n// Bloque 4: Instrucciones\r\nfunction render_bloque_ficha_instrucciones($block, $content = \'\', $is_preview = false) {\r\n    $instrucciones = get_field(\'instrucciones\');\r\n    if ($instrucciones) : ?>\r\n        <div class=\"ficha-card ficha-instrucciones\">\r\n            <h3>???? Instrucciones</h3>\r\n            <div class=\"instrucciones-contenido\">\r\n                <?php echo nl2br(esc_html($instrucciones)); ?>\r\n            </div>\r\n        </div>\r\n    <?php endif;\r\n}\r\n','Bloques ACF para Fichas Educativas','','draft','closed','closed','','bloques-acf-para-fichas-educativas','','','2026-01-14 17:03:14','2026-01-14 17:03:14','',0,'http://localhost:8080/?post_type=wpcode&#038;p=65',0,'wpcode','',0),
