(106,1,'2026-01-15 09:40:52','2026-01-15 09:40:52','// Cargar librerĂ­as PDF y JS personalizado para fichas\r\nadd_action(\'wp_enqueue_scripts\', function () {\r\n    if (is_singular(\'ficha\')) {\r\n        \r\n        // html2canvas (necesario para html2pdf)\r\n        wp_enqueue_script(\r\n            \'html2canvas\',\r\n            \'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js\',\r\n            array(),\r\n            \'1.4.1\',\r\n            true\r\n        );\r\n        \r\n        // jsPDF\r\n        wp_enqueue_script(\r\n            \'jspdf\',\r\n            \'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js\',\r\n            array(),\r\n            \'2.5.1\',\r\n            true\r\n        );\r\n        \r\n        // html2pdf (depende de html2canvas y jspdf)\r\n        wp_enqueue_script(\r\n            \'html2pdf\',\r\n            \'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js\',\r\n            array(\'html2canvas\', \'jspdf\'),\r\n            \'0.10.1\',\r\n            true\r\n        );\r\n        \r\n        // JS personalizado de fichas (depende de html2pdf)\r\n        wp_enqueue_script(\r\n            \'fichas-js\',\r\n            get_stylesheet_directory_uri() . \'/js/fichas.js\',\r\n            array(\'html2pdf\'),\r\n            \'1.1\', // Incrementa versiĂłn para forzar recarga\r\n            true\r\n        );\r\n    }\r\n}, 999);\r\n','Cargar JS y LibrerĂ­as PDF - Fichas Educativas','','draft','closed','closed','','crear-terminos-taxonomias-fichas','','','2026-02-02 11:24:02','2026-02-02 11:24:02','',0,'http://localhost:8080/wpcode/crear-terminos-taxonomias-fichas/',0,'wpcode','',0),
