(130,1,'2026-01-19 10:19:56','2026-01-19 10:19:56','/**\r\n * Preservar emojis UTF-8MB4 en importaciones de WP All Import hacia ACF\r\n * Campo: contenido_ficha_html\r\n */\r\n\r\n// 1. Forzar conexiĂłn UTF-8MB4 antes de cada importaciĂłn\r\nadd_action(\'pmxi_before_xml_import\', function($import_id) {\r\n    global $wpdb;\r\n    $wpdb->query(\"SET NAMES \'utf8mb4\'\");\r\n    $wpdb->query(\"SET CHARACTER SET utf8mb4\");\r\n    $wpdb->query(\"SET character_set_connection=utf8mb4\");\r\n}, 10, 1);\r\n\r\n// 2. Evitar que ACF sanitice el campo HTML\r\nadd_filter(\'acf/update_value/name=contenido_ficha_html\', function($value, $post_id, $field) {\r\n    // Devolver el valor sin modificar (sin sanitizaciĂłn)\r\n    return $value;\r\n}, 10, 3);\r\n\r\n// 3. Evitar que WP All Import sanitice campos ACF\r\nadd_filter(\'pmxi_acf_custom_field_value\', function($value, $pid, $name) {\r\n    if ($name === \'contenido_ficha_html\') {\r\n        // No aplicar wp_kses ni otras funciones de limpieza\r\n        return $value;\r\n    }\r\n    return $value;\r\n}, 10, 3);\r\n\r\n// 4. Preservar emojis al actualizar post meta directamente\r\nadd_filter(\'sanitize_post_meta_contenido_ficha_html\', function($meta_value, $meta_key, $object_type) {\r\n    // Devolver sin sanitizar\r\n    return $meta_value;\r\n}, 10, 3);\r\n','Preservar emojis en importaciones ACF','','publish','closed','closed','','preservar-emojis-en-importaciones-acf','','','2026-01-19 10:19:56','2026-01-19 10:19:56','',0,'http://localhost:8080/?post_type=wpcode&#038;p=130',0,'wpcode','',0),
