(145,1,'2026-01-20 11:54:54','2026-01-20 11:54:54','/**\r\n * Genera breadcrumbs de navegaciĂłn con Schema.org\r\n * NO confundir con .ficha-breadcrumb-taxonomias (badges dentro de header)\r\n * VERSIĂN 2.0: Soporte para tema-estacional con prioridad sobre asignatura\r\n */\r\nfunction fichas_breadcrumbs() {\r\n    if (is_front_page()) {\r\n        return;\r\n    }\r\n    \r\n    $breadcrumbs = array();\r\n    $home = array(\r\n        \'name\' => \'Inicio\',\r\n        \'url\' => home_url(\'/\')\r\n    );\r\n    \r\n    $breadcrumbs[] = $home;\r\n    \r\n    // SINGLE FICHA\r\n    if (is_singular(\'ficha\')) {\r\n        $post_id = get_the_ID();\r\n        \r\n        // Nivel educativo\r\n        $niveles = get_the_terms($post_id, \'nivel-educativo\');\r\n        if ($niveles && !is_wp_error($niveles)) {\r\n            $nivel = $niveles[0];\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $nivel->name,\r\n                \'url\' => home_url(\'/\' . $nivel->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // Curso\r\n        $cursos = get_the_terms($post_id, \'curso\');\r\n        if ($cursos && !is_wp_error($cursos)) {\r\n            $curso = $cursos[0];\r\n            $nivel_slug = $nivel ? $nivel->slug : \'primaria\';\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $curso->name,\r\n                \'url\' => home_url(\'/\' . $nivel_slug . \'/\' . $curso->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // PRIORIDAD: Tema Estacional > Asignatura\r\n        $tema_estacional = get_the_terms($post_id, \'tema-estacional\');\r\n        $asignaturas = get_the_terms($post_id, \'asignatura\');\r\n        \r\n        if ($tema_estacional && !is_wp_error($tema_estacional)) {\r\n            // SI HAY TEMA ESTACIONAL: Mostrar ese\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $tema_estacional[0]->name,\r\n                \'url\' => home_url(\'/\' . ($nivel ? $nivel->slug : \'infantil\') . \'/estacional/\')\r\n            );\r\n        } elseif ($asignaturas && !is_wp_error($asignaturas) && $asignaturas[0]->slug !== \'todas\') {\r\n            // SI NO HAY ESTACIONAL pero SĂ asignatura vĂĄlida (y no es \"Todas\"): Mostrar asignatura\r\n            $asignatura = $asignaturas[0];\r\n            $nivel_slug = $nivel ? $nivel->slug : \'primaria\';\r\n            $curso_slug = $curso ? $curso->slug : \'1-primaria\';\r\n            $breadcrumbs[] = array(\r\n                \'name\' => $asignatura->name,\r\n                \'url\' => home_url(\'/\' . $nivel_slug . \'/\' . $curso_slug . \'/\' . $asignatura->slug . \'/\')\r\n            );\r\n        }\r\n        \r\n        // Ficha actual\r\n        $breadcrumbs[] = array(\r\n            \'name\' => get_the_title(),\r\n            \'url\' => \'\'\r\n        );\r\n    }\r\n    \r\n    // PĂGINA PERSONALIZADA (Hubs)\r\n    if (is_page()) {\r\n        // Detectar por URL\r\n        $url_parts = explode(\'/\', trim($_SERVER[\'REQUEST_URI\'], \'/\'));\r\n        \r\n        // Hub Nivel (ej: /primaria/)\r\n        if (count($url_parts) == 1 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(), // Usa el tĂ­tulo de la pĂĄgina\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n        // Hub Curso (ej: /primaria/1-primaria/)\r\n        elseif (count($url_parts) == 2 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($url_parts[0]),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\')\r\n            );\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(),\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n        // PĂĄgina Asignatura (ej: /primaria/1-primaria/matematicas/)\r\n        elseif (count($url_parts) == 3 && in_array($url_parts[0], [\'primaria\', \'infantil\', \'secundaria\'])) {\r\n            // Nivel\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($url_parts[0]),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\')\r\n            );\r\n            // Curso\r\n            $curso_title = str_replace(\'-\', \' \', $url_parts[1]);\r\n            $breadcrumbs[] = array(\r\n                \'name\' => ucfirst($curso_title),\r\n                \'url\' => home_url(\'/\' . $url_parts[0] . \'/\' . $url_parts[1] . \'/\')\r\n            );\r\n            // Asignatura actual\r\n            $breadcrumbs[] = array(\r\n                \'name\' => get_the_title(),\r\n                \'url\' => \'\'\r\n            );\r\n        }\r\n    }\r\n    \r\n    // RENDERIZAR\r\n    if (count($breadcrumbs) > 1) {\r\n        echo \'<nav class=\"site-breadcrumbs\" aria-label=\"Breadcrumb\">\';\r\n        echo \'<ol class=\"breadcrumbs-list\" itemscope itemtype=\"https://schema.org/BreadcrumbList\">\';\r\n        \r\n        foreach ($breadcrumbs as $position => $crumb) {\r\n            $is_last = ($position == count($breadcrumbs) - 1);\r\n            \r\n            echo \'<li class=\"breadcrumb-nav-item\" itemprop=\"itemListElement\" itemscope itemtype=\"https://schema.org/ListItem\">\';\r\n            \r\n            if (!empty($crumb[\'url\']) && !$is_last) {\r\n                echo \'<a href=\"\' . esc_url($crumb[\'url\']) . \'\" itemprop=\"item\">\';\r\n                echo \'<span itemprop=\"name\">\' . esc_html($crumb[\'name\']) . \'</span>\';\r\n                echo \'</a>\';\r\n            } else {\r\n                echo \'<span itemprop=\"name\">\' . esc_html($crumb[\'name\']) . \'</span>\';\r\n            }\r\n            \r\n            echo \'<meta itemprop=\"position\" content=\"\' . ($position + 1) . \'\" />\';\r\n            echo \'</li>\';\r\n            \r\n            if (!$is_last) {\r\n                echo \'<li class=\"breadcrumb-separator\" aria-hidden=\"true\">âș</li>\';\r\n            }\r\n        }\r\n        \r\n        echo \'</ol>\';\r\n        echo \'</nav>\';\r\n    }\r\n}\r\n','Genera breadcrumbs (migas de pan) con Schema.org','','publish','closed','closed','','genera-breadcrumbs-migas-de-pan-con-schema-org','','','2026-01-29 10:30:03','2026-01-29 10:30:03','',0,'http://localhost:8080/wpcode/genera-breadcrumbs-migas-de-pan-con-schema-org/',0,'wpcode','',0),
(146,1,'2026-01-21 09:21:26','2026-01-21 09:21:26','add_action(\'wp_enqueue_scripts\', function() {\r\n    if (is_singular(\'ficha\') && current_user_can(\'administrator\')) {\r\n        wp_enqueue_script(\r\n            \'html2canvas\',\r\n            \'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js\',\r\n            array(),\r\n            \'1.4.1\',\r\n            true\r\n        );\r\n    }\r\n});\r\n','Cargar html2canvas solo en fichas para imagen pinterest','','draft','closed','closed','','cargar-html2canvas-solo-en-fichas','','','2026-02-04 09:10:33','2026-02-04 09:10:33','',0,'http://localhost:8080/wpcode/cargar-html2canvas-solo-en-fichas/',0,'wpcode','',0),
(148,1,'2026-01-21 09:40:55','2026-01-21 09:40:55','/* ============================================\n   FIX FOOTER - ANCHO COMPLETO\n   ============================================ */\n\n/* Footer principal a ancho completo */\nfooter,\n.site-footer {\n    width: 100vw !important;\n    max-width: 100% !important;\n    margin-left: calc(-50vw + 50%) !important;\n    margin-right: calc(-50vw + 50%) !important;\n    padding: 0 !important;\n    background: #2571A3; /* Color exacto */\n    box-sizing: border-box;\n}\n\n/* Contenedor interno centrado */\nfooter .content-footer {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 40px 20px;\n    width: 100%;\n    box-sizing: border-box;\n}\n\n/* Widgets del footer */\nfooter .widget-content-footer {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));\n    gap: 30px;\n    width: 100%;\n}\n\nfooter .widget-area {\n    color: white;\n}\n\nfooter .widget-area h2 {\n    color: white;\n    font-size: 1.25rem;\n    margin-bottom: 15px;\n    border-bottom: 2px solid rgba(255, 255, 255, 0.3);\n    padding-bottom: 10px;\n}\n\nfooter .widget-area ul {\n    list-style: none;\n    padding: 0;\n    margin: 0;\n}\n\nfooter .widget-area ul li {\n    margin-bottom: 8px;\n}\n\nfooter .widget-area a {\n    color: rgba(255, 255, 255, 0.8);\n    text-decoration: none;\n    transition: color 0.3s ease;\n}\n\nfooter .widget-area a:hover {\n    color: white;\n    text-decoration: underline;\n}\n\n/* Copyright con dominio fichas.es */\nfooter .content-footer::after {\n    content: \'Â© 2026 Fichas.es - Fichas Educativas Interactivas\';\n    display: block;\n    text-align: center;\n    margin-top: 30px;\n    padding-top: 20px;\n    border-top: 1px solid rgba(255, 255, 255, 0.2);\n    color: rgba(255, 255, 255, 0.7);\n    font-size: 0.9rem;\n}\n\n/* Responsive */\n@media (max-width: 768px) {\n    footer .widget-content-footer {\n        grid-template-columns: 1fr;\n        gap: 20px;\n    }\n    \n    footer .content-footer {\n        padding: 30px 15px;\n    }\n}\n','asap-child','','publish','closed','closed','','asap-child','','','2026-01-21 09:42:34','2026-01-21 09:42:34','',0,'http://localhost:8080/asap-child/',0,'custom_css','',0),
(149,1,'2026-01-21 09:40:55','2026-01-21 09:40:55','/* ============================================\n   FOOTER MEJORADO - ESTILO PROFESIONAL\n   ============================================ */\n\nfooter {\n    background: linear-gradient(135deg, #2c7da0 0%, #1a5a7f 100%);\n}\n\n/* AĂ±adir lĂ­nea superior decorativa */\nfooter::before {\n    content: \'\';\n    display: block;\n    height: 4px;\n    background: linear-gradient(90deg, #667eea 0%, #764ba2 100%);\n    width: 100%;\n}\n\n/* Copyright/crĂ©ditos al final */\nfooter .content-footer::after {\n    content: \'Â© 2026 Pau Castells - Fichas Educativas\';\n    display: block;\n    text-align: center;\n    margin-top: 30px;\n    padding-top: 20px;\n    border-top: 1px solid rgba(255, 255, 255, 0.2);\n    color: rgba(255, 255, 255, 0.7);\n    font-size: 0.9rem;\n}\n','asap-child','','inherit','closed','closed','','148-revision-v1','','','2026-01-21 09:40:55','2026-01-21 09:40:55','',148,'http://localhost:8080/?p=149',0,'revision','',0),
(151,1,'2026-01-21 09:42:34','2026-01-21 09:42:34','/* ============================================\n   FIX FOOTER - ANCHO COMPLETO\n   ============================================ */\n\n/* Footer principal a ancho completo */\nfooter,\n.site-footer {\n    width: 100vw !important;\n    max-width: 100% !important;\n    margin-left: calc(-50vw + 50%) !important;\n    margin-right: calc(-50vw + 50%) !important;\n    padding: 0 !important;\n    background: #2571A3; /* Color exacto */\n    box-sizing: border-box;\n}\n\n/* Contenedor interno centrado */\nfooter .content-footer {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 40px 20px;\n    width: 100%;\n    box-sizing: border-box;\n}\n\n/* Widgets del footer */\nfooter .widget-content-footer {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));\n    gap: 30px;\n    width: 100%;\n}\n\nfooter .widget-area {\n    color: white;\n}\n\nfooter .widget-area h2 {\n    color: white;\n    font-size: 1.25rem;\n    margin-bottom: 15px;\n    border-bottom: 2px solid rgba(255, 255, 255, 0.3);\n    padding-bottom: 10px;\n}\n\nfooter .widget-area ul {\n    list-style: none;\n    padding: 0;\n    margin: 0;\n}\n\nfooter .widget-area ul li {\n    margin-bottom: 8px;\n}\n\nfooter .widget-area a {\n    color: rgba(255, 255, 255, 0.8);\n    text-decoration: none;\n    transition: color 0.3s ease;\n}\n\nfooter .widget-area a:hover {\n    color: white;\n    text-decoration: underline;\n}\n\n/* Copyright con dominio fichas.es */\nfooter .content-footer::after {\n    content: \'Â© 2026 Fichas.es - Fichas Educativas Interactivas\';\n    display: block;\n    text-align: center;\n    margin-top: 30px;\n    padding-top: 20px;\n    border-top: 1px solid rgba(255, 255, 255, 0.2);\n    color: rgba(255, 255, 255, 0.7);\n    font-size: 0.9rem;\n}\n\n/* Responsive */\n@media (max-width: 768px) {\n    footer .widget-content-footer {\n        grid-template-columns: 1fr;\n        gap: 20px;\n    }\n    \n    footer .content-footer {\n        padding: 30px 15px;\n    }\n}\n','asap-child','','inherit','closed','closed','','148-revision-v1','','','2026-01-21 09:42:34','2026-01-21 09:42:34','',148,'http://localhost:8080/?p=151',0,'revision','',0),
